Script.parameter:
endpoints = {};

endpoints.acis = {};
/*
endpoints.lifecyclerule = {};
endpoints.people = {};
endpoints.roles = {};
*/

for (ep in endpoints) {
	var alName = "_testITIMRestConnector_" + ep;
	task.logmsg("Starting " + alName + "...");
	endpoints[ep].al = main.startAL(alName)
}

var completed = {};

do {
	var stillRunning = 0;

	for (ep in endpoints) {
		if (!completed[ep]) {
			var state = endpoints[ep].al.getCurrentState()
			if (!state.equalsIgnoreCase("Completed")) {
				stillRunning++
			} else {
				var stats = endpoints[ep].getStats();
				task.logmsg("Test of " + ep + " completed with "
							+ stats.err + " Errors, "
							+ stats.get + stats.lookup + " GETs, "
							+ stats.add + " POSTs, "
							+ stats.mod + " PUTs and "
							+ stats.del + " DELETEs")
				completed[ep] = true
			}

			task.sleep(1)
		}
	}
} while (stillRunning > 0)

Branch.ScriptCondition:
if ((cnt++ % 10) == 0) {
	task.logmsg("Loop #" + cnt + "  Free Memory: " + java.lang.Runtime.getRuntime().freeMemory());	
}

return cnt <= maxLoops

