__forceQueryMode = true;

function control(paramName, val) {
	this.paramName = paramName;
	this.val = work.getString(paramName) || val;

	this.getLabel = function() {
		return __paramLabels[this.paramName] || this.paramName;
	}

	this.formatLog = function(msg) {
		return this.getLabel() + " (" + this.paramName + ") " + msg;
	}

	this.getText = function() {
		if (typeof this.val === 'boolean') {
			return this.val.toString();
		}
		return this.val;
	}

	this.setText = function(val) {
		main.logmsg(this.formatLog("setText: " + val));
		this.val = val;
	}

	this.removeAll = function() {
		main.logmsg(this.formatLog("removeAll"));
	}

	this.add = function(arg) {
		main.logmsg(this.formatLog("add: " + arg));	
	}

	this.select = function(arg) {
		main.logmsg(this.formatLog("select: " + arg));
		this.val = arg;
	}

	this.getItems = function() {
		return ["all","the","items"];
	}

	this.getSelectedItem = function() {
		return this.val;
	}

	this.getSelectionIndex = function() {
		return 5; // ITIM/IGI
	}

	this.getSelection = function() {
		if (typeof this.val === 'boolean') {
			return this.val;
		}
		return false;
	}

	this.getItemCount = function() {
		return 5;
	}

	this.getItem = function(index) {
		return "item-" + index;
	}

	this.setVisible = function(enable) {
		main.logmsg(this.formatLog((enable ? "ENABLING" : "disabling")));
	}

	this.setEnabled = function(enable) {
		main.logmsg(this.formatLog((enable ? "ENABLING" : "disabling")));
	}

	return this;
}

