function checkMemory() {
	var freeMem = java.lang.Runtime.getRuntime().freeMemory();
	var totalMem = java.lang.Runtime.getRuntime().totalMemory();
	var maxMem = java.lang.Runtime.getRuntime().maxMemory();
}

function prettyTime(ms) {
	if (ms == null || isNaN(ms)) return "0 seconds";

	ms = parseInt(ms, 10);

	var totalSeconds = Math.floor(ms / 1000);

	var days = Math.floor(totalSeconds / 86400);
	totalSeconds = totalSeconds % 86400;

	var hours = Math.floor(totalSeconds / 3600);
	totalSeconds = totalSeconds % 3600;

	var minutes = Math.floor(totalSeconds / 60);
	var seconds = totalSeconds % 60;

	var parts = [];

	if (days > 0)    parts.push(days + " day"    + (days    !== 1 ? "s" : ""));
	if (hours > 0)   parts.push(hours + " hour"   + (hours   !== 1 ? "s" : ""));
	if (minutes > 0) parts.push(minutes + " minute" + (minutes !== 1 ? "s" : ""));
	if (seconds > 0 || parts.length === 0)
		parts.push(seconds + " second" + (seconds !== 1 ? "s" : ""));

	return parts.join(" ");
}

function prettyMem(bytes) {
	if (bytes == null || isNaN(bytes)) return "0 B";
	bytes = parseInt(bytes, 10);

	var KB = 1024;
	var MB = KB * 1024;
	var GB = MB * 1024;

	if (bytes >= GB) {
		return (bytes / GB).toFixed(2) + " GB";
	}
	if (bytes >= MB) {
		return (bytes / MB).toFixed(2) + " MB";
	}
	if (bytes >= KB) {
		return (bytes / KB).toFixed(2) + " KB";
	}
	return bytes + " B";
}

