function normalizeAuthMethod(v) {
	// 0 None, 1 Basic, 2 Bearer Token, 3 API Key, 4 OAuth2, 5 ITIM/IGI, 6 Custom
	if (v == null) return 0;

	// If already a number-ish, accept it
	try {
		var n = system.toInt(String(v));
		if (n >= 0 && n <= 6) return n;
	} catch (e) { }

	var s = String(v).toLowerCase().trim();
	if (s === "" || s === "none") return 0;
	if (s.indexOf("basic") >= 0) return 1;
	if (s.indexOf("bearer") >= 0) return 2;
	if (s.indexOf("api") >= 0 && s.indexOf("key") >= 0) return 3;
	if (s.indexOf("oauth") >= 0) return 4;
	if (s.indexOf("itim") >= 0 || s.indexOf("igi") >= 0) return 5;
	if (s.indexOf("custom") >= 0) return 6;
	return 0;
}

// @@FIX: Updated initialize() to use new RESTCLIENT with proper auth parameters
// Builds the args object dynamically based on selected auth_method
function initialize() {
	if (__initialized) return;
	__initialized = true;

	eval(system.getScriptText("RESTCLIENT class")); // Load HTTP Client class

	// @@FIX: Build constructor args based on auth_method selection
	var args = {
		baseUrl: form.getControl("url").getText(),
		contextRoot: form.getControl("contextRoot").getText() || "/itim/rest",
		auth_method: form.getControl("auth_method").getText(), // "none", "basic"
		debug: debug() // true => debug output
	};

	// @@FIX: Add auth-specific parameters based on selected method
	var authMethodIndex = normalizeAuthMethod(args.auth_method);

	if (authMethodIndex === 1) { // Basic Auth
		args.basic_username = form.getControl("basic_username").getText();
		args.basic_password = form.getControl("basic_password").getText();

	} else if (authMethodIndex === 2) { // API Key
		args.api_key_value = form.getControl("api_key_value").getText();
		args.api_key_name = form.getControl("api_key_name").getText();
		args.api_key_location = form.getControl("api_key_location").getText();

	} else if (authMethodIndex === 3) { // Bearer Token
		args.bearer_token = form.getControl("bearer_token").getText();
		args.token_header_name = form.getControl("token_header_name").getText();
		args.token_prefix = form.getControl("token_prefix").getText();

	} else if (authMethodIndex === 4) { // OAuth2
		// @@FIX: Add all OAuth2 parameters from the form
		args.oauth2_token_url = form.getControl("oauth2_token_url").getText();
		args.oauth2_auth_url = form.getControl("oauth2_auth_url").getText();
		args.client_id = form.getControl("client_id").getText();
		args.client_secret = form.getControl("client_secret").getText();
		args.scope = form.getControl("scope").getText();
		args.audience = form.getControl("audience").getText();
		args.redirect_uri = form.getControl("redirect_uri").getText();
		args.use_pkce = form.getControl("use_pkce").getSelection(); // checkbox
		args.oauth2_username = form.getControl("oauth2_username").getText();
		args.oauth2_password = form.getControl("oauth2_password").getText();
		args.oauth2_token_auth_method = form.getControl("oauth2_token_auth_method").getText();
		args.oauth2_token_header_name = form.getControl("oauth2_token_header_name").getText();
		args.oauth2_token_prefix = form.getControl("oauth2_token_prefix").getText();
		args.client_key_password = form.getControl("client_key_password").getText();
	} else if (authMethodIndex == 5) { // ITIM/IGI
		args.itim_username = form.getControl("itim_username").getText();
		args.itim_password = form.getControl("itim_password").getText();
		args.itim_login_endpoint = form.getControl("itim_login_endpoint").getText();
		args.itim_me_endpoint = form.getControl("itim_me_endpoint").getText();
		args.itim_csrf_header = form.getControl("itim_csrf_header").getText();
	} else if (authMethodIndex == 6) { // Custom
		args.custom_script = form.getControl("custom_script").getText();
	}	
	// authMethodIndex === 0 (none) or 5 (custom) don't need additional parameters

	// Create the HTTP client with appropriate auth configuration
	__http = new RESTCLIENT(args);

	fetchSchema();
}

// Wrap each REST request in a Standby signal
function makeRequest(args) {
	var reply = null;
	var target = null;

	// Show a wait cursor while the Connector initializes
	form.setWaitCursor();

	try {
		reply = __http.makeRequest(args);
	} catch (ex) {
		__schema = null;
		throw "MakeRequest from " + (args.where || "?") + "\n" + ex;
	} finally {
		// Restore the normal cursor
		form.setNormalCursor();
	}

	return reply;
}

// Returns the schema each time it is called
function fetchSchemaEveryTime() {
	__schema = null;

	return fetchSchema();
}

// Return the openAPI schema
function fetchSchema() {
	if (__schema) return __schema;

	initialize();

	try {
		var replyEntry = makeRequest({
			verb: "GET",
			expectedReturnType: "entry",
			url: form.getControl("schema").getText(),
			ctype: "application/json",
			where: "fetchSchema()"
		});
	} catch (ex) {
		var msg = "fetchSchema() failed with error: " + ex;
		alert(msg);
		throw msg;
	}

	if (replyEntry == null) throw "Unable to request openAPI schema";

	// Load the SCHEMA class
	eval(system.getScriptText("SCHEMA class")); // Load SCHEMA handling class

	__schema = new SCHEMA(replyEntry.getString("http.bodyAsString"), "JSON");

	return __schema;
}

