// Return the action based on the mode setting
function modeBasedAction() {
	var mode = config.getParent().getMode();
	switch (mode.toLowerCase()) {
		case "iterator": return "GET";
		case "update": return "POST";
		case "lookup": return "GET";
		case "delete": return "DELETE";
		case "addonly": return "POST";
	}
}

function fetchServers(selectedPath) {
	initialize();

	selectedPath = selectedPath || form.getControl("path").getText();

	updateDropdown("contextRoot",
		["paths", selectedPath, "servers"],
		"Cannot fetch servers for selected Endpoint");
}

// Update the dropdown with operations for the selected path
function fetchActions() {
	initialize();

	var selectedPath = form.getControl("path").getText();

	alert("fetchActions() for " + selectedPath);

	var endpointDetails = __schema.getChildren(["paths", selectedPath]);
	if (endpointDetails == null) {
		form.alert("The Endpoint Path set must be defined in the OpenAPI schema.");
		return;
	}

	updateModes(selectedPath,
		"Cannot fetch HTTP verbs for the specified Path: " + selectedPath);

	fetchServers(selectedPath);
}

// Fetch the parameters (with descriptions) and populate the text box - appending to what is already there
function fetchParameters() {
	initialize();

	var params = __schema.getParameters(form.getControl("path").getText(),
		modeBasedAction());

	updateTextBox("parameters", params);
}

__hashMap = new java.util.HashMap();
function updateModes(selectedPath, errorMsg) {
	initialize();

	var verbs = __schema.getChildren(["paths", selectedPath]);

	if (!verbs) {
		form.alert("Endpoint Path parameter must be set before modes can be determined");
		return;
	}

	if (__schema == null) return;

	// We have to go through all endpoints to see if there are any that match the selected one, but include the endpoint UID and that support PUT or DELETE
	var allVerbs = {};
	var endpointPath = __schema.endpointPathIterator.getFirst(selectedPath);
	while (endpointPath) {
		if (endpointPath.equalsIgnoreCase(selectedPath)
			|| (endpointPath.startsWith(selectedPath + "/{") && endpointPath.endsWith("}"))) {
			var verbs = __schema.getChildren(["paths", endpointPath]);
			for (verb in verbs) {
				var verbStr = verb.getName();
				switch (verbStr) {
					case "get": allVerbs.get = true; break;
					case "put": allVerbs.modify = true; break;
					case "post": allVerbs.add = true; break;
					case "delete": allVerbs.del = true; break;
				}
			}
		}

		endpointPath = __schema.endpointPathIterator.getNext();
	}

	var modes = __hashMap;
	modes.clear();

	if (allVerbs.del) {
		modes.put("Delete", true);
	}
	if (allVerbs.get && allVerbs.modify && allVerbs.add) {
		modes.put("Update", true);
	}
	if (allVerbs.add) {
		modes.put("AddOnly", true);
	}
	if (allVerbs.get) {
		modes.put("Iterator", true);
		modes.put("Lookup", true);
	}

	var modesSupported = modes.keySet().toArray().toString(", ");

	alert("----> Supported modes for this path are: " + modesSupported);

	form.getControl("action").setText(modesSupported);
}

// Updating a textbox control
function updateTextBox(controlName, paramsArray) {
	// First get the existing value and parse it (if possible)
	var oldValue = form.getControl(controlName).getText().trim();
	var useParams = {};

	// Go through the passed parameters and set those that are not already set
	for (var i = 0; i < paramsArray.length; i++) {
		var param = paramsArray[i];
		if (param["in"] != "path" && param.name.indexOf("CSRFToken") < 0) {
			// Add to the list if not something for the path itself
			useParams[param.name] = system.splitString(param.description, ".")[0]
				+ (system.splitString(param.description, ".")[1]);
		}
	}

	// Parse the old text value into individual parameter settings and put in an Entry
	if (oldValue) {
		var lines = system.splitString(oldValue, "\n");
		for (var line in lines) {
			var parts = system.splitString(line, "=");
			if (parts.length > 1) {
				// Overwrite any discovered parameters with previously set values
				useParams[parts[0].trim()] = parts[1].trim();
			}
		}
	}

	// Get the useParams property names (param names) and sort them
	__arrayList.clear();
	for (var propName in useParams) {
		alert("    Adding " + propName);
		__arrayList.add(propName);
	}

	paramNames = __arrayList.toArray();
	java.util.Arrays.sort(paramNames);
	alert("    ParamNames: " + paramNames.length + " item(s)");

	var newParamText = "";
	for (var i = 0; i < paramNames.length; i++) {
		var paramName = paramNames[i];
		alert("    Getting " + paramName);
		newParamText += paramName + "=" + useParams[paramName] + "\n";
	}

	// Finally, update the control
	form.getControl(controlName).setText(newParamText);
}

// Update dropdown based on API
function updateDropdown(controlName, path, errorMsg) {
	var ndx;

	try {
		initialize();

		if (!path) {
			form.alert("updateDropdown() - Path parameter must be set");
			return;
		}

		var subtree = __schema.getChildren(path);

		if (subtree == null) {
			path.shift();
			form.alert("Invalid Endpoint Path: " + path.toString());
			return;
		}

	} catch (ex) {
		var msg = "Updating Dropdown " + controlName + " using path " + path + "Cannot get API schema\n" + errorMsg + "\n" + ex;
		alert(msg);
		throw msg;
	}

	combo = form.getControl(controlName);

	// Get the current value and set the selection point if it matches a path
	var currentValue = (combo.getText() || "").trim();

//	main.logmsg("Removing all from combo: " + controlName);
	combo.removeAll(); // Empty drop-down

	// Now to sort these alphabetically
	__arrayList.clear();
	for (var child in subtree) {
		// See if the sub-attribute has the same name, so this represents a JS Array
		// Fancy footwork for dealing with path > servers, with an array of servers
		if (child.getName() == path[path.length - 1]) {
			// In which case, we add its child
			__arrayList.add(child.getChildNodes()[0].getValue());
		} else {
			__arrayList.add(child.getName());
		}
	}

	var sortedArray = __arrayList.toArray();
	java.util.Arrays.sort(sortedArray);

	for (ndx in sortedArray) {
		if (!(controlName == "path"  // Remove Paths that end with /{item id}
			&& ndx.indexOf("/{") > 0
			&& ndx.endsWith("}"))) {
			combo.add(ndx);
		}
	}

	var pos = 0;

	// But only if a value has been set at all
	if (currentValue != "") {

		// If this value is not prepended with forward slash, then add it
		if (!currentValue.startsWith("/")) {
			currentValue = "/" + currentValue;
		}

		var len = combo.getItemCount();
		for (pos = 0; pos < len; pos++) {
			var val = combo.getItem(pos);

			if (val.equalsIgnoreCase(currentValue) ||
				val.toLowerCase() > currentValue.toLowerCase()) {
				break; // Found a match
			}
		}
	}

	pos = (pos < sortedArray.length) ? pos : 0;
	combo.select(pos);

	//main.logmsg("UpdateDropdown set to position " + pos);
}

// Empty out both Item and Object dropdowns
function clearDropdowns() {
	form.getControl("path").removeAll();
}

