// Set the auth strategy from the auth_method dropdown 
// and make only relevant params visible
function setauth_method() {
	var control = form.getControl("auth_method");
	var value = control.getText() || "";

	if (!value) {
		value = "None"
	}

	control.setText(value);

	setAuthMethod()
}

function setAuthMethod() {
    disableAllControls();

    var method = form.getControl("auth_method").getSelectionIndex();
    if (method < 0) {
        method = 0;
    }
    form.getControl("auth_method").select(method);

    var enableSet = __sectionParameters[method];
    for (var controlName in enableSet) {
        setVisible(controlName, true);
    }
}

// Make the named parameter field visible
function setVisible(controlName, enableIt) {
	if (typeof(enableIt) == "undefined") enableIt = true;
	var verb = enableIt ? "ENABLING" : "disabling"

	//main.logmsg("---> " + verb + ": " + controlName);

	var control = form.getControl(controlName);
	control.setVisible(enableIt);

	return; // Skip the rest for now
	for (var child in children) {
		if (child.toString().startsWith("Label")) {
			//main.logmsg(">" + verb + " " + child.toString() + " <" + child.getText() + "> " + child.getClass());
			child.setVisible(enableIt);
		}
	}
}

// Make all parameters fields invisible (org.eclipse.swt.widgets.Control)
function disableAllControls() {
	//main.logmsg("Form: " + form.getClass())

	for (var controlName in __allControls) {
		var control = form.getControl(controlName);		
		setVisible(controlName, false);
	}
}

// Select the OAuth2 scope and enable the right parameters
function selectScope() {
	// First disable all other parameters than 'scope'
	disableAllControls();

	// Now turn the drop-down selection 	
	var scope = form.getControl("scope").getSelectionIndex();
	if (scope < 0 || scope > 2) {
		scope = 0
	}
	form.getControl("scope").select(scope);
	var enableSet = __oauth2Parameters[scope];

	//main.logmsg("Enabling for scope: " + form.getControl("scope").getText());
	for (var controlName in enableSet) {
		setVisible(controlName, true)
	}
}

