function logmsg(lvl, msg) {
	if (typeof (lvl) == "undefined") {
		lvl = "INFO";
		msg = ""
	} else
		if (typeof (msg) == "undefined") {
			msg = lvl;
			lvl = "INFO"
		}

	if (task instanceof com.ibm.di.server.AssemblyLine) {
		task.logmsg(lvl, msg)
	} else {
		main.logmsg(lvl, msg)
	}
}

function parseKeyValuePair(keyValueTxt) {
	// 1) Split the single line into key/value (no decoding)
	var pair = /^([^=]+)=(.*)$/.exec(keyValueTxt);
	if (!pair) {
		logmsg("Not a key=value line: " + keyValueTxt);
		return null
	} else {
		pair[1] = pair[1].trim();
		pair[2] = pair[2].trim();
	}

	return {
		key: pair[1],
		value: pair[2]
	}
}

// Regex: matches (attr=value) terms but naturally skips '(|', '(&', '(!', etc.
//var pairRe = /\(\s*([A-Za-z][A-Za-z0-9-]*(?:;[A-Za-z0-9-]+)*)\s*=\s*([^()]*)\s*\)/g;
var pairRe = /\((?![|&!])\s*([A-Za-z][A-Za-z0-9-]*(?:;[A-Za-z0-9-]+)*)\s*=\s*([^()]*)\s*\)/g;

// RFC4515 unescape: turns \2a -> '*', \28 -> '(', etc.
function ldapUnescape(s) {
	if (s == null) return s;
	return s.replace(/\\([0-9A-Fa-f]{2})/g, function (_, hex) {
		return String.fromCharCode(parseInt(hex, 16));
	});
}

// Returns an array of {attr: ..., value: ...}
function parseLdapEqPairs(filter) {
	// Make sure there is are parenthesis around the filter
	filter = (filter || "").trim()
	if (filter && filter.charAt(0) !== '(') filter = '(' + filter + ')';

	var pairs = [];
	var re = /\((?![|&!])\s*([A-Za-z][A-Za-z0-9-]*(?:;[A-Za-z0-9-]+)*)\s*=\s*([^()]*)\s*\)/g;
	var m;
	while ((m = re.exec(filter)) !== null) {
		var attr = m[1];
		var val = ldapUnescape(m[2].replace(/^\s+|\s+$/g, ""));
		pairs.push({ attr: attr, value: val });
	}
	return pairs;
}

// Craft the query string for this request
function craftQueryString(args) {
	var path = args.path;
	var connParams = args.connParams;
	var useParams = args.epParams || {};
	//	var entry = __reuseEntry; __reuseEntry.removeAllAttributes();   NOT USED
	var where = args.where || "?";
	var filter = (args.filter || "").trim();
	var queryString = "";

	// Parse this into the list of key/value pairs and their operators
	var pairs = parseLdapEqPairs(filter);

	// Now reconstruct a single line suitable as a set of query paramters
	var useFilter = "";
	var alreadyHandled = {};
	for (var pairIndex in pairs) {
		var pair = pairs[pairIndex];
		useFilter += ((useFilter == "") ? "" : "&") + pair.attr + "=" + pair.value
		alreadyHandled[pair.attr.trim().toLowerCase()] = true;
	}

	// Now to add the parameters set in the Connector Connection field that are not already in the query parameter list
	var paramsSetting = connParams.parameters || "";
	var params = paramsSetting.split(/\s*(?:[;,]|\r?\n)\s*/);
	for (var i = 0; i < params.length; i++) {
		var param = params[i];
		if (param.trim() == "") continue;

		var pair = parseKeyValuePair(param);
		// Skip field values already contained in the Search Criteria
		if (!pair || !pair.key || !pair.value
			|| alreadyHandled[pair.key.trim().toLowerCase()]) continue; // Ignore lines that are not key=value

		// Append to queryString
		queryString += ((queryString == "") ? "" : "&") + pair.key.trim() + "=" + pair.value.trim()
	}

	if (useFilter != "") {
		queryString += ((queryString == "") ? "" : "&") + useFilter.trim();
	}

	// Now to ensure that required parameters are set
	args.queryString = queryString;
	//checkQueryString(args);

	return queryString
}

// checks that query params are defined in the schema and throws and exception when required params are not present
function checkQueryString(args) {
	var queryString = args.queryString;
	var where = args.where || "UNDEFINED"; // GET, POST, PUT or DELETE
	var verb = (args.verb || "undefined").trim().toUpperCase();
	var connParams = args.connParams;
	var useParams = args.epParams || {};
	var schemaParams = {};

	schemaParams = __schema.getParameters(connParams.path, verb);
	/*
	if (__schema.schemaObj.paths[connParams.path]
	&& __schema.schemaObj.paths[connParams.path][verb]
	&& __schema.schemaObj.paths[connParams.path][verb].parameters) {
	schemaParams = __schema.schemaObj.paths[connParams.path][verb].parameters;
	}
	*/

	var queryParams = system.splitString(queryString, "&");

	// First collect the required parameter list
	var allParams = {};
	var requiredParams = {};
	for (var i in schemaParams) { // schemaParams is a JS array
		var param = schemaParams[i];
		allParams[param.name] = true;
		if (param.required && (param["in"] == "query")) {
			requiredParams[param.name] = false; // Initialize as false = NOT SEEN
		}
	}

	// Now see what is not defined in the schema and what may be missing
	for (var queryParam in queryParams) {
		var pair = system.splitString(queryParam, "=");
		var key = pair[0];
		var value = pair[1];
		//		if (!allParams[key]) {
		//			logmsg("WARN", "Parameter not specified in the OpenAPI schema: " + key)
		//		}

		if (requiredParams[key] === false) {
			requiredParams[key] = true
		}
	}

	var missing = "";
	for (var paramName in requiredParams) {
		if (!requiredParams[paramName]) {
			missing += ((missing == "") ? "" : ", ") + paramName;
		}
	}
	if (missing != "") {
		throw "Required query string parameter(s) missing: " + missing
		+ ".\nThese must either be in the Link Criteria or the Parameters setting of the Connector"
	}
}

function fixUrl(url) {
	if (url.charAt(url.length - 1) != "/") {
		return url + "/";
	} else {
		return url;
	}
}

function debug() {
	return __debug;
}

function normalizeAuthMethod(v) {
	// 0 None, 1 Basic, 2 Bearer Token, 3 API Key, 4 OAuth2, 5 ITIM/IGI, 6 Custom
	if (v == null) return 0;
	try {
		var n = system.toInt(String(v));
		if (n >= 0 && n <= 6) return n;
	} catch (e) { }
	var s = String(v).toLowerCase().trim();
	if (s === "" || s === "none") return 0;
	if (s.indexOf("basic") >= 0) return 1;
	if (s.indexOf("bearer") >= 0) return 2;
	if (s.indexOf("api") >= 0 && s.indexOf("key") >= 0) return 3;
	if (s.indexOf("oauth") >= 0) return 4;
	if (s.indexOf("itim") >= 0 || s.indexOf("igi") >= 0) return 5;
	if (s.indexOf("custom") >= 0) return 6;
	return 0;
};

function canonicalAuthMethod(v) {
	var s = String(v || "").toLowerCase().trim();
	if (s === "" || s === "none") return "none";
	if (s.indexOf("basic") >= 0) return "basic";
	if (s.indexOf("bearer") >= 0) return "bearer";
	if (s.indexOf("api") >= 0 && s.indexOf("key") >= 0) return "apikey";
	if (s.indexOf("oauth") >= 0) return "oauth2";
	if (s.indexOf("itim") >= 0 || s.indexOf("igi") >= 0) return "itim";
	if (s.indexOf("custom") >= 0) return "custom";
	return "none";
};


function normalizeOAuthScope(v) {
	// 0 client credentials, 1 auth code, 2 password
	if (v == null) return 0;

	try {
		var n = system.toInt(String(v));
		if (n >= 0 && n <= 2) return n;
	} catch (e) { }

	var s = String(v).toLowerCase().trim();
	if (s.indexOf("client") >= 0) return 0;
	if (s.indexOf("authorization") >= 0 || s.indexOf("code") >= 0) return 1;
	if (s.indexOf("password") >= 0) return 2;
	return 0;
}

function resetConnector() {
	__initialized = false;
	__resultSetIndex = 0;

	if (!__resultSet) __resultSet = new java.util.ArrayList();
	else __resultSet.clear();

	if (typeof list != "undefined") list.clear();

	// Always pull latest params before constructing RESTCLIENT
	refreshParameters();

	if (typeof RESTCLIENT == "undefined" || !RESTCLIENT) {
		eval(system.getScriptText("RESTCLIENT class"));
	}

	// Build args dynamically based on selected auth method
	var args = {
		baseUrl: __parameters.url,
		contextRoot: __parameters.contextRoot,
		debug: debug(),
		auth_method: __parameters.auth_method,
		auth_method_index: __parameters.auth_method_index
	};

	var m = __parameters.auth_method_index;

	if (m === 1) { // Basic
		args.basic_username = __parameters.basic_username || __parameters.username;
		args.basic_password = __parameters.basic_password || __parameters.password;

	} else if (m === 2) { // Bearer Token
		args.bearer_token = __parameters.bearer_token;
		args.token_header_name = __parameters.token_header_name || "Authorization";
		args.token_prefix = __parameters.token_prefix || "Bearer";

	} else if (m === 3) { // API Key
		args.api_key_name = __parameters.api_key_name;
		args.api_key_value = __parameters.api_key_value || __parameters.apikey;
		args.api_key_location = __parameters.api_key_location || "Header";

	} else if (m === 4) { // OAuth2
		// IMPORTANT:
		// args.scope = numeric grant selector (0/1/2)
		// args.oauth2_scope = textual OAuth scope string
		args.scope = __parameters.scope; // normalized numeric index (0/1/2) from refreshParameters()
		args.oauth2_scope = __parameters.oauth2_scope; // textual scope string

		args.oauth2_token_url = __parameters.oauth2_token_url;
		args.oauth2_auth_url  = __parameters.oauth2_auth_url;
		args.client_id        = __parameters.client_id;
		args.client_secret    = __parameters.client_secret;

		args.redirect_uri = __parameters.redirect_uri;
		args.audience     = __parameters.audience;
		args.use_pkce     = (__parameters.use_pkce == true || String(__parameters.use_pkce).toLowerCase() == "true");

		// Password grant
		args.oauth2_username = __parameters.oauth2_username;
		args.oauth2_password = __parameters.oauth2_password;

		// Token endpoint auth method + header formatting
		args.oauth2_token_auth_method = __parameters.oauth2_token_auth_method;
		args.oauth2_token_header_name = __parameters.oauth2_token_header_name || "Authorization";
		args.oauth2_token_prefix      = __parameters.oauth2_token_prefix || "Bearer";
	} else if (m === 5) { // ITIM/IGI
		args.itim_username = __parameters.itim_username;
		args.itim_password = __parameters.itim_password;
		args.itim_login_endpoint = __parameters.itim_login_endpoint || "/itim/j_security_check";
		args.itim_me_endpoint = __parameters.itim_me_endpoint || "/itim/rest/systemusers/me";
		args.itim_csrf_header = __parameters.itim_csrf_header || "CSRFToken";

	} else if (m === 6) { // Custom
		args.custom_script = __parameters.custom_script;
	}

	__http = new RESTCLIENT(args);
}

function objToAttributes(obj, entry) {
	if (!obj || !entry) return;

	for (var attName in obj) {
		if (!attName.startsWith("_")) {
			var attValue = obj[attName];
			var attValueJSON = '{"' + attName + '": ' + toJson(attValue) + '}';
			var attValueEntry = entry.fromJSON(attValueJSON);
			entry.setAttribute(attValueEntry[attName])
		}
	}
}

// Turn the JS object returned from a call into the global entry object
function toEntry(thisItem) {
	var connParams = refreshParameters();
	var entry = system.newEntry();

	//main.logmsg("toEntry() - includeUIDs: " + connector.getParam("includeUIDs"))

	if (thisItem._links) {
		// Now to convert this to a TDI entry
		if (thisItem._links.erparent) {
			entry.orgId = href2UID(thisItem._links.erparent.href);
		}
		entry.uid = href2UID(thisItem._links.self.href);
	}

	// Now add attributes to the entry object
	objToAttributes(thisItem, entry);
	objToAttributes((thisItem._attributes ? thisItem._attributes : {}), entry);

	//main.logmsg("toEntry - Complete: \n" + entry)

	return entry // Returning only for the sake of the Connections Event logic
}

