}

// Utility function to return a file as a string
function loadFileToString(filepath) {
	var sb = new java.lang.StringBuilder();
	var file = system.openFileForInput(filepath);
	var line;
	while ((line = file.readLine()) != null) {
		sb.append(line + "\n");
	}
	return sb.toString();
}

// Return the openAPI schema
function fetchSchema() {
	var schemaEntry,
		schemaSpec;
	//alert("Fetching schema...")
	if (__schema) return __schema;

	if (__debug || true) {
		//		var schemaSpec = loadFileToString("_Restify/sample_itim_schema.yaml") // @@TODO should NOT be based on a file
		//		var schemaSpec = system.getScriptText("sample_itim_schema_yaml")
		schemaSpec = system.getScriptText("json_schema")
	} else {
		schemaEntry = __http.makeRequest({
			verb: "GET",
			url: __parameters.schema,
			expectedReturnType: "Entry",
			authUrl: __parameters.authUrl,
			ctype: "application/json",
			contextRoot: "",
			where: "fetchSchema()"
		});
		schemaSpec = schemaEntry.getString("http.bodyAsString")
	}

	// Load the SCHEMA class
	eval(system.getScriptText("SCHEMA class")) // Load SCHEMA handling class

	//alert("Creating SCHEMA object");
	__schema = new SCHEMA(schemaSpec, "YAML");

	return __schema
}

// Parse the openAPI schema
function parseSchema() {
	if (__schema) return __schema;

	// See if the schema object is cached in the Java RT Server. Must be unique per service
	var cacheKey = "OpenAPI_schema::" + (__parameters.url + __parameters.contextRoot + __parameters.schema);
	var cacheKeyTS = cacheKey + "_TIMESTAMP";

	__schema = java.lang.System.getProperties().get(cacheKey);
	__schemaTimestamp = java.lang.System.getProperties().get(cacheKeyTS) || 0;

	var now = (new java.util.Date()).getTime();
	var age = (__schemaTimestamp > 0) ? ((now - __schemaTimestamp) / 3600000) : 9999999;

	// Get the cache lifespan parameter setting
	var cacheLifespanSetting = connector.getParam("max_cache_age");
	var cacheLifespan
	try {
		cacheLifespan = system.toInt(cacheLifespanSetting)
	} catch (ex) {
		cacheLifespan = 0
	}

	// Debug output
	if (__schema != null) {
		java.lang.System.out.println("Found schema cached at " + new java.util.Date(__schemaTimestamp.doubleValue()));
		java.lang.System.out.println("Schema cache age (hours): " + age + "   max age: " + cacheLifespan)
	}

	// If cache lifespan is set (greater than 0) then caching is enabled
	if (cacheLifespan >= 1 && __schema != null) {
		// Check if the cache has expired
		if (age < cacheLifespan) {
			java.lang.System.out.println("---- using cached schema");
			return __schema
		}
	}

	java.lang.System.out.println("--<< fetching schema");
	__schema = fetchSchema();

	// If so configured, then cache the schema object
	if (cacheLifespan >= 1) {
		java.lang.System.out.println("> caching schema");
		java.lang.System.getProperties().put(cacheKey, __schema);
		java.lang.System.getProperties().put(cacheKeyTS, now)
	}

	return __schema
}

function refreshParameters() {
	var path = connector.getParam("path");
	if (!path) throw new java.lang.RuntimeException(
		"Path parameter has not been set for Connector: " + connector.getName()
	);

	__parameters = {};

	// Read everything from the form
	for (var paramName in __paramNames) {
		__parameters[paramName] = connector.getParam(paramName);
	}

	// Normalize / default a few critical values
	__parameters.url         = (__parameters.url || "").trim();
	__parameters.contextRoot = (__parameters.contextRoot || "").trim();
	__parameters.schema      = (__parameters.schema || "/openapi").trim();
	__parameters.path        = (__parameters.path || "").trim();

	// ---- Auth method ----
	// RESTCLIENT expects args.auth_method (NOT auth_method_index)
	__parameters.auth_method = canonicalAuthMethod(__parameters.auth_method);
	__parameters.auth_method_index = normalizeAuthMethod(__parameters.auth_method);

	// ---- OAuth2 scope/grant dropdown index vs textual scope ----
	// Your dropdown index should be passed as args.scope (RESTCLIENT parses it as an integer index)
	// Your textual OAuth scope string must be a DIFFERENT parameter (e.g. oauth2_scope / scope_text)
	//
	// 1) ensure args.scope is numeric index (0/1/2)
	__parameters.scope = normalizeOAuthScope(__parameters.scope);

	// 2) ensure text scope lives in oauth2_scope (or scope_text) and is trimmed
	// (Pick ONE canonical name for the RESTCLIENT: oauth2_scope is a good choice)
	__parameters.oauth2_scope = String(__parameters.oauth2_scope || "").trim();

	// ---- Legacy compatibility ----
	// Keep legacy fields populated so older RESTCLIENT versions won’t break
	if (!__parameters.username && (__parameters.basic_username || __parameters.itim_username)) {
		__parameters.username = __parameters.basic_username || __parameters.itim_username;
	}
	if (!__parameters.password && (__parameters.basic_password || __parameters.itim_password)) {
		__parameters.password = __parameters.basic_password || __parameters.itim_password;
	}
	if (!__parameters.apikey && __parameters.api_key_value) {
		__parameters.apikey = __parameters.api_key_value;
	}

	// Old code used authUrl (mostly for ITIM login); OAuth has oauth2_auth_url
	if (!__parameters.authUrl && __parameters.oauth2_auth_url) {
		__parameters.authUrl = __parameters.oauth2_auth_url;
	}

	__contextRoot = __parameters.contextRoot;

	return __parameters;
}

function beautifyValue(val) {
	//main.logmsg("beautifyValue() - " + val);
	if (typeof (val) != "object") return val;

	try {
		var newVal = toJson(val);

		//main.logmsg("!!! It IS JSON !!!");
		if (val.description) newVal = val.description;
		//main.logmsg("--- Returning: '" + newVal + "'");
		return newVal;
	} catch (ex) {
		return val
	}
}

// Figure out which endpoint param is for the base path and grab the value from the entry
// If the entry passed is null, then don't go looking for the Attribute
function extractUID(entry, epParams, connParams) {
	var uid = "";
	var uidattName = null;

	for (var i in epParams) {
		var param = epParams[i];
		if (param["in"] == "path") {
			uidattName = param.name;
			break
		}
	}

	if (!entry) {
		uid = "*not gonna be used for anything*"
	} else
		if (uidattName) {
			var uidAtt = entry[uidattName];
			if (uidAtt) uid = uidAtt.getValue(0)
		}

	if (!uid) throw new java.lang.Exception("The UID attribute must be mapped out: " + uidattName)

	return {
		value: uid,
		name: uidattName
	}
}

// Calls function in the _schema object // @@TODO Remove the action parameter and use the mode, or specific function calling to set the action. ALSO do not permit operations with no corresponding actions (Franz?)
function getParameters(path, verb) {
	if (!__schema) fetchSchema();

	var params = __schema.getParameters(path, verb);
	//if (params == null || params == [] || params == {}) throw "ERROR: " + action + " is not supported for this endpoint " + path;
	if (params == null) throw "Schema Violation: " + verb + " is not supported for this endpoint " + path;
	return params
}


function getAcceptType(path, verb) {
