// Grab the next entry Selected for Iterator mode
function getNextEntry() {
	initialize();
	// First get the next item from __resultSet
	do {
		if (__resultSetIndex >= __resultSet.size()) {
			result.setStatus(0);
			return null;
		}
		var thisItemHref = __resultSet.get(__resultSetIndex++);
