// To detect if a value is an array or not.
function isArray(val) {
	return val && ((val instanceof Array))
}

// Create the request payload for a POST or PUT operation based on its schema example
function createPayloadObject(path, verb, entry) {
	// First get the location of the example schema
	path = path.trim();
	var savePath = path;
	verb = verb.trim().toUpperCase();
	var contentType = __schema.getContentType(path, verb);
	var payloadIsArray = false;

	// First we have to get the right endpoint for this verb
	if (verb == "PUT" || verb == "DELETE") {
		path = __schema.endpointPathIterator.getFirst(path);
		while (path != null && !(path.indexOf("/{") > 0 && path.endsWith("}"))) {
			path = __schema.endpointPathIterator.getNext()
		}
	}

	var pathToSchema = __schema.getChildren(["paths",
		path,
		verb,
		"requestBody",
		"content",
		contentType]);

	// If no schema found, then return the entire entry
	if (pathToSchema == null) throw "ITIMRestConnector.createPayloadObject() unable to find schema: " + verb + " for " + path;

	// First check if the schema specifies an array of 'items'
	if (pathToSchema.type && pathToSchema.type.getValue() == "array") {
		payloadIsArray = true;
		pathToSchema = pathToSchema.items
	}

	if (pathToSchema.oneOf != null) {
		for (var oneOf in pathToSchema.oneOf) {
			logmsg(oneOf.toString())
		}
	}

	while (pathToSchema != null && pathToSchema.getName() != "$ref") {
		for (var subAtt in pathToSchema) {
			if (subAtt.getName() == "$ref") {
				pathToSchema = subAtt;
				break
			}

			pathToSchema = subAtt
		}
	}

	// Now to look up this schema definition
	var schemaDef = __schema.getChildren(pathToSchema.getValue().substring(2).split("/"));
	var properties = schemaDef.properties;
	if (!properties) throw "ITIMRestConnector.createPayloadObject() unable to find schema.properties: " + verb + " for " + path;

	var schemaAttributes = properties._attributes;

	// See if attributes are defined elsewhere
	if (schemaAttributes["$ref"]) {
		schemaDef = __schema.getChildren(schemaAttributes["$ref"].getValue().substring(2).split("/"));
		schemaAttributes = schemaDef.properties
	}

	// Prepare to start building the payload using the two reusable Entry objects
	var payloadObj = {};
	__reuseEntry.removeAllAttributes(); // This for the actual payload
	__reuseEntry2.removeAllAttributes(); // Use this to collect _attributes
	var useEntry = __reuseEntry;

	// Maybe the schema is show under examples
	if (schemaAttributes.example) {
		schemaAttributes = schemaAttributes.example
	}

	// The REST API is context sensitive for field names, so take consideration of this
	// Go through schema and include mapped attribute values in the payload, ensuring correct case as we go
	var attSchemas = [properties, schemaAttributes];
	var attributesLeft = entry.clone();
	for (var i in attSchemas) {
		for (var att in attSchemas[i]) {
			var targetIsArray = (att.type && (att.type.getValue() == "array") || false);
			var attName = att.getName();

			// Is this attribute defined somewhere else...?
			if (attName == "$ref") {
				var schemaPath = att.getValue();
				schemaDef = __schema.getChildren(schemaPath.substring(2).split("/"));
				var valueDef = schemaDef.properties
			}

			if (attName == "_attributes") continue;

			var mappedAtt = entry[attName];
			if (mappedAtt) {
				var attValue = mappedAtt.getValue();
				var type = att.type ? att.type.getValue() : "";
				if (i == 0) {
					// If 'properties' then add directly to the payloadObj
					useEntry = __reuseEntry // for the payload object
				} else {
					useEntry = __reuseEntry2 // for _attributes
				}

				newAtt = system.newAttribute(attName);
				/*
				if (type == "array" && false) { // Drop this and make mapping a little trickiers
				// We must add an additional layer to our Entry/DOM tree
				newAtt.appendChild(system.newAttribute(attName));
				newAtt = newAtt.getChildNodes()[0]
				}
				*/
				var children = mappedAtt.getChildNodes();
				for (var child in children) {
					if (child instanceof com.ibm.di.entry.Attribute) {
						newAtt.appendChild(child)
					}
				}
				newAtt.addValues(mappedAtt);

				useEntry[attName] = newAtt;
				attributesLeft.removeAttribute(attName)
			}
		}
	}

	// Now add any attributes not moved over the payload. The schema might be an example, and more attributes can be written
	for (var attribute in attributesLeft) {
		attName = attribute.getName()
		var newAtt = system.newAttribute(attName);

		var children = attribute.getChildNodes();
		for (var child in children) {
			if (child instanceof com.ibm.di.entry.Attribute) {
				newAtt.appendChild(child)
			}
		}

		newAtt.addValues(attribute);

		__reuseEntry2[attName] = newAtt;
	}

	payloadObj = fromJson(__reuseEntry.toJSON());
	payloadObj._attributes = fromJson(__reuseEntry2.toJSON());

	return payloadObj
}

// Function for AddOnly mode
function putEntry(entryArg) {
	initialize();
	// entryArg is optional and is for easier testing
	if (entryArg) entry = entryArg;

	// Always get the latest parameter settings
	var connParams = refreshParameters();
	var usePath = connParams.path;
	// Get the parameters for this path + actoin
	var epParams = getParameters(connParams.path, "PUT");

	// Check if POST is a supported verb for this path
	if (!__schema.pathSupportsVerb(connParams.path, "POST")) {
		throw "POST/Add not supported for this path: " + connParams.path
	}

	var payloadObj = createPayloadObject(connParams.path, "POST", entry);

	//	payloadObj = fromJson(system.getScriptText("lifeCycleRuleJSON"));
	//	payloadObj = fromJson(system.getScriptText("identityPolicyAddJSON"));
	//	payloadObj = fromJson(system.getScriptText("systemRoleAddJSON"));
	//	payloadObj = system.getScriptText("personAddJSON")

	var ctype = getContentType(connParams.path, "POST");
	var accept = getAcceptType(connParams.path, "POST");

	var body = toJson(payloadObj).replace("[[", "[").replace("]]", "]");

	try {
		// Make the REST call
		var reply = __http.makeRequest({
			verb: "POST",
			url: usePath,
			//	accept: "application/vnd.ibm.isim-v1+json",
			returnType: "entry",
			ctype: ctype,
			accept: accept,
			expectedReturnType: entry,
			where: "putEntry()",
			body: body
		});

		//main.logmsg("selectEntries for Data - Reply: " + com.ibm.di.entry.Entry.fromJSON(toJson(reply)));

		//var resultEntry = toEntry(reply);
		//logmsg("putEntry() - " + entry.fromJSON(toJson(reply)));

		return reply
	} catch (ex) {
		logmsg("ERROR", ex);
		throw ex
	}
}

function modEntry() {
	initialize();
	var usePath;

	// Always get the latest parameter settings
	var connParams = refreshParameters();
	var entryWithUID = connector.getFirstFindEntry() || system.newEntry();

	// Check if PUT are a supported methods for this path
	if (!__schema.pathSupportsVerb(connParams.path, "PUT")) {
		throw "PUT/modify not supported for this path: " + connParams.path
	}

	usePath = connParams.path;
	var uid = entryWithUID.uid;
	if (!uid) throw "No UID for item found in entry returned by Find operation"

	// Now set up the url for a mod operation
	var p = usePath.lastIndexOf("/"); // Remove everying after the slash so we can append the uid
	usePath = (p > 0) ? usePath.substring(0, p) + uid : usePath + "/" + uid;

	// Get the parameters for this path + actoin
	var epParams = getParameters(connParams.path, "PUT");

	var payloadObj = createPayloadObject(connParams.path, "PUT", entry);
	var body = toJson(payloadObj);

	var ctype = getContentType(connParams.path, "PUT");
	var accept = getAcceptType(connParams.path, "PUT");

	try {
		// Make the REST call
		var reply = __http.makeRequest({
			verb: "PUT",
			url: usePath,
			ctype: ctype,
			accept: accept,
			ishref: true,
			body: body,
			where: "modEntry()"
		});

		for (var attName in reply) {
			var attValue = reply[attName];
			entry[attName] = attValue
		}

		return entry
	} catch (ex) {
		var msg = "Modification failed: " + ex;
		logmsg("ERROR", msg);
		throw new java.lang.Exception(msg)
	}
}

function deleteEntry() {
	initialize();
	// Always get the latest parameter settings
	var connParams = refreshParameters();
	// Get the parameters for this path + actoin
	var epParams = getParameters(connParams.path, "DELETE");

	var uid = entry.getString("uid");
	var usePath = connParams.path + "/" + uid;

	// Check that DELETE is supported for this path
	if (!__schema.pathSupportsVerb(connParams.path, "DELETE")) {
		throw "DELETE not supported for this path: " + connParams.path
	}

	var accept = getAcceptType(connParams.path, "DELETE");

	try {
		// Make the REST call
		var reply = __http.makeRequest({
			verb: "DELETE",
			url: usePath,
			accept: accept,
			where: "deleteEntry()",
			body: entry.toJSON()
		});

		return entry
	} catch (ex) {
		logmsg("ERROR", ex);
		throw ex
	}
}

// Single regex: grabs (attr = value), also ~=, >=, <=, and presence (attr=*)
var TERM_RE = /\(\s*([^()~<>=:!]+)\s*(=|~=|>=|<=)\s*([^\)]*?)\s*\)/g;

// Optional: unescape LDAP \xx hex (e.g., \2a => '*', \28 => '(')
function ldapUnescape(s) {
	if (!s) return s;
	s = s.replace(/\\([0-9A-Fa-f]{2})/g, function (_, hh) {
		return String.fromCharCode(parseInt(hh, 16));
	});
	// collapse any leftover single backslash escapes
	return s.replace(/\\(.)/g, "$1");
}

// Finding an entry only works as direct read using the UID
function findEntry(searchCriteria) {
	initialize();
	// Allows you to pass in the search criteria for easier testing
	searchCriteria = searchCriteria || search;

	connector.clearFindEntries();

	var scriptedCrit = searchCriteria.getScriptFilter();
	var resultEntry;

	// Now to handle the Link Crit format, simplifying it for use as query strings
	var ldapFilter = searchCriteria.getLDAPFilter();
	var filter = ldapFilter || scriptedCrit;

	useFilter = filter;

	// Always get the latest parameter settings
	var connParams = refreshParameters();
	// Get the parameters for this path + actoin
	var epParams = getParameters(connParams.path, "GET");

	// Check if GET is a supported verb for this path
	if (!__schema.pathSupportsVerb(connParams.path, "GET")) {
		throw "GET/Read not supported for this path: " + connParams.path
	}

	// Now see if this is a Read operation based on uid
	var re = /\(?\s*id\s*=\s*([^\s)]+)/i;
	var checkForIdSearch = re.exec(useFilter);
	var usePath = connParams.path;

	queryString = "";
	if (checkForIdSearch) {
		var uid = checkForIdSearch[1];

		// Now set up the url for a read operation
		var p = usePath.lastIndexOf("/"); // Remove everying after the slash so we can append the uid
		usePath = (p > 0) ? usePath.substring(0, p) + uid : usePath + "/" + uid;
		useFilter = checkForIdSearch[0]; // The regex gets rid of paranthesis too
	} else {
		// Now for queryParameters
		queryString = craftQueryString({
			connParams: connParams,
			path: usePath,
			epParams: epParams,
			action: connParams.action,
			entry: entry,
			filter: useFilter,
			verb: "GET",
			where: "findEntry()"
		})
	}

	// Grab accept type before appending query string parameters
	var accept = getAcceptType(connParams.path, "GET");

	// If there is a queryString, prepend it with ?
	usePath = queryString ? usePath + "?" + queryString : usePath;

	//main.logmsg("putEntry - making call");
	try {
		entry.removeAllAttributes();

		// Make the REST call
		var reply = __http.makeRequest({
			verb: "GET",
			url: usePath,
			accept: accept,
			where: "findEntry()",
			findEntry: true
		});

		if (reply == null || reply.length == 0) {
			result.setStatus(0);
			return null
		}

		// Else continue to request details for each item found
		result.setStatus(1);

		var thisItemHref;
		var resultEntry;
		var entryArray = [];

		entryArray = (reply instanceof Array) ? reply : [reply]; // Reads only return a single item, not an array like find ops do

		for (var i = 0; i < entryArray.length; i++) {
			// Now to read in the full Entry based on the href
			try {
				if (!entryArray[i]._links) {
					thisItem = entryArray[i]
				} else {
					thisItemHref = entryArray[i]._links.self.href.substring(__contextRoot.length);

					var accept = getAcceptType(connParams.path, "GET");

					// Make the REST call to get the complete item
					var thisItem = __http.makeRequest({
						verb: "GET",
						url: thisItemHref,
						ishref: true,
						accept: accept,
						where: "findEntry()"
					});

					if (thisItem == null) {
						continue
					}
				}

			} catch (ex) {
				logmsg("ERROR", "Error reading individual item from selection: " + ex);
				throw ex
			}

			// Now to convert this to a TDI entry
			resultEntry = toEntry(thisItem, entry);
			connector.addFindEntry(resultEntry);
			entry.merge(resultEntry)
		}

	} catch (ex) {
		logmsg("ERROR", "Error searching for entry: " + ex);
		throw ex
	}
}

