	var params = __schema.getParameters(path, verb);
	//if (params == null || params == [] || params == {}) throw "ERROR: " + action + " is not supported for this endpoint " + path;
	if (params == null) throw "Schema Violation: " + verb + " is not supported for this endpoint " + path;
	return params
}


