// This is the class that provides methods for making HTTP requests
// 20250116 1116 Created
// ...
// 20251229 1538 Tighted up makeRequest() handling of body and ctype - only for post and put
// 20260107 1445 Updated makeRequest to skip adding a request header prop if the value passed in is null
// 20260202 1413 Added Current User Path to the Connection tab and RESTCLIENT constructor
// 20260215 1730 Removed the meURL parameter, hardcoded now for ITIM
// 20260220 1444 Redone using Claude to enhance for more Auth strategies
// 20260225 1256 Corrected mixup in parameter names and types (auth_method + auth_method_index)
// 20260229 1421 Trying for Basic Auth now
// 20260229 1706 Fixed assembleURL to remove repeating parts, like root context in the passed base
// 20260302 1948 Fixed a lot of stuff after analysis by Chat
// 20260303 1000 Session store: all per-auth state in this.sessions[name]
//               Fixed basic auth to use basic_username/basic_password
//               Fixed .startsWith() -> .indexOf()===0 for ES3 compatibility
// 20260304 2048 Removed default /itim/rest contextRoot
// 20260306 1447 Trying to make a clean version of the config
// 20260306 1503 Corrected a bug in makeRequest, passing entryDetails(entry) and should have passed entry
//
// TO DO:
//   1. log_level
//   2. retry params
//
//
//
// NOTES:
//   * Uses its own this.logmsg() for controlled logging
//
// SESSION STORE DESIGN
// --------------------
// All stateful authentication data (tokens, cookies, CSRF, LTPA) is stored
// in a named session object rather than directly on 'this'. This provides:
//
//   1) Clean separation of auth state from configuration.
//   2) Multiple independent sessions if ever needed (e.g. dual-auth flows).
//   3) Easy reset/invalidation of a single session without touching others.
//
// Sessions are accessed via:
//   this.getSession()          -- default session (keyed by auth_method)
//   this.getSession("mykey")   -- named session (created on first access)
//   this.clearSession()        -- reset the default session
//   this.clearSession("mykey") -- reset a named session
//
// Each session object contains:
//   gotToken      {boolean}   -- initial token/login has been completed
//   accessToken   {string}    -- OAuth2 access token (or null)
//   refreshToken  {string}    -- OAuth2 refresh token (or null)
//   tokenExpiry   {long}      -- OAuth2 expiry timestamp ms (or null)
//   cookies       {Attribute} -- HTTP cookie jar
//   CSRFToken     {string}    -- CSRF header value (ITIM)
//   LTPAToken2    {string}    -- LTPA2 cookie value (ITIM)
//
// Default session key is this.auth_method ("oauth2", "itim", "basic" etc).
// Override by passing params.sessionKey in makeRequest() calls.

function RESTCLIENT(args) {
    this.baseUrl     = (args.baseUrl || "").trim();
    this.contextRoot = args.contextRoot || "";

	this.normalizeAuthMethod = function(v) {
		// 0 None, 1 Basic, 2 Bearer Token, 3 API Key, 4 OAuth2, 5 ITIM/IGI, 6 Custom
		if (v == null) return 0;
		try {
			var n = system.toInt(String(v));
			if (n >= 0 && n <= 6) return n;
		} catch (e) { }
		var s = String(v).toLowerCase().trim();
		if (s === "" || s === "none") return 0;
		if (s.indexOf("basic") >= 0) return 1;
		if (s.indexOf("bearer") >= 0) return 2;
		if (s.indexOf("api") >= 0 && s.indexOf("key") >= 0) return 3;
		if (s.indexOf("oauth") >= 0) return 4;
		if (s.indexOf("itim") >= 0 || s.indexOf("igi") >= 0) return 5;
		if (s.indexOf("custom") >= 0) return 6;
		return 0;
	};

	this.canonicalAuthMethod = function(v) {
		var s = String(v || "").toLowerCase().trim();
		if (s === "" || s === "none") return "none";
		if (s.indexOf("basic") >= 0) return "basic";
		if (s.indexOf("bearer") >= 0) return "bearer";
		if (s.indexOf("api") >= 0 && s.indexOf("key") >= 0) return "apikey";
		if (s.indexOf("oauth") >= 0) return "oauth2";
		if (s.indexOf("itim") >= 0 || s.indexOf("igi") >= 0) return "itim";
		if (s.indexOf("custom") >= 0) return "custom";
		return "none";
	};

	this.auth_method       = this.canonicalAuthMethod(args.auth_method);
	this.auth_method_index = (typeof args.auth_method_index === "undefined")
		? this.normalizeAuthMethod(args.auth_method)
		: (parseInt(args.auth_method_index, 10) || 0);

    // Basic Authentication
    if (this.auth_method === "basic") {
        this.basic_username = args.basic_username || args.username;
        this.basic_password = args.basic_password || args.password;
    }

    // Bearer Token Authentication
    if (this.auth_method === "bearer") {
        this.bearer_token      = args.bearer_token || args.token;
        this.token_header_name = args.token_header_name || "Authorization";
        this.token_prefix      = args.token_prefix || "bearer";
    }

	// API Key Authentication
	if (this.auth_method === "apikey") {
	    this.api_key_name     = args.api_key_name    || "X-API-Key";
	    this.api_key_value    = args.api_key_value   || args.apikey;
	    this.api_key_location = args.api_key_location || "header";
	}

    // OAuth 2.0 Authentication
	if (this.auth_method === "oauth2") {
		this.oauth2_token_url = args.oauth2_token_url || args.tokenurl;
		this.oauth2_auth_url  = args.oauth2_auth_url  || args.authurl;
		this.client_id        = args.client_id        || args.clientid;
		this.client_secret    = args.client_secret    || args.clientsecret;
		// 0=client_credentials, 1=authorization_code, 2=password
		this.oauth2_grant_index = (args.oauth2_grant_index != null)
			? (parseInt(args.oauth2_grant_index, 10) || 0)
			: ((args.scope != null) ? (parseInt(args.scope, 10) || 0) : 0);
		this.oauth2_scope            = (args.oauth2_scope || "").trim();
		this.audience                = args.audience;
		this.redirect_uri            = args.redirect_uri || args.redirecturi;
		this.use_pkce                = (args.use_pkce == true || String(args.use_pkce).toLowerCase() === "true");
		this.oauth2_username         = args.oauth2_username;
		this.oauth2_password         = args.oauth2_password;
		this.oauth2_token_auth_method = args.oauth2_token_auth_method || args.tokenauthmethod;
		this.oauth2_token_header_name = args.oauth2_token_header_name || "Authorization";
		this.oauth2_token_prefix      = args.oauth2_token_prefix      || "bearer";
	}

    // ITIM/IGI Authentication
    if (this.auth_method === "itim") {
        this.itim_username       = args.itim_username       || args.username;
        this.itim_password       = args.itim_password       || args.password;
        this.itim_login_endpoint = args.itim_login_endpoint || "/itim/j_security_check";
        this.itim_me_endpoint    = args.itim_me_endpoint    || "/itim/rest/systemusers/me";
        this.itim_csrf_header    = args.itim_csrf_header    || "CSRFToken";
    }

    // Custom Authentication
    if (this.auth_method === "custom") {
        this.custom_auth_script = args.custom_script;
    }

	// Legacy aliases still used by some callers
	this.username = this.basic_username || this.itim_username || args.username || "";
	this.password = this.basic_password || this.itim_password || args.password || "";

	if (this.auth_method === "oauth2") {
	    this.scope_index              = (typeof args.scope === "undefined") ? 0 : (parseInt(args.scope, 10) || 0);
	    this.scope                    = (typeof args.scope === "undefined") ? "" : (args.oauth2_scope || "").trim();
	    this.oauth2_token_header_name = this.oauth2_token_header_name || "Authorization";
	    this.oauth2_token_prefix      = this.oauth2_token_prefix      || "bearer";
	}

	this.debug = args.debug || 1;

	// HTTP Client Connector
	this.http         = system.getConnector("ibmdi.HTTPClient");
	this.requestEntry = system.newEntry();

	// -------------------------------------------------------------------------
	// SESSION STORE
	// -------------------------------------------------------------------------
	// All per-authentication runtime state lives here, not directly on 'this'.
	// Use getSession() / clearSession() to access or reset a session.
	// -------------------------------------------------------------------------
	this.sessions = {};

	// Returns the named session, creating it fresh if it does not yet exist.
	// Default name is this.auth_method.
	this.getSession = function(name) {
		name = name || this.auth_method;
		if (!this.sessions[name]) {
			this.sessions[name] = {
				gotToken:     false,   // initial login/token fetch done?
				accessToken:  null,    // OAuth2 access token
				refreshToken: null,    // OAuth2 refresh token
				tokenExpiry:  null,    // OAuth2 expiry (ms since epoch)
				cookies:      system.newAttribute("http.Cookie"), // cookie jar
				CSRFToken:    null,    // CSRF header value (ITIM)
				LTPAToken2:   null     // LTPA2 cookie (ITIM)
			};
		}
		return this.sessions[name];
	};

	// Wipes a session so it will re-authenticate on next use.
	this.clearSession = function(name) {
		name = name || this.auth_method;
		delete this.sessions[name];
		this.logmsg("Session cleared: " + name);
	};

	// Returns true if the named session has completed initial authentication.
	this.sessionReady = function(name) {
		name = name || this.auth_method;
		return !!(this.sessions[name] && this.sessions[name].gotToken);
	};

	// -------------------------------------------------------------------------
	// Backward-compat helpers for code that still reads this.CSRFToken /
	// this.cookies directly. Delegates to the default session.
	// -------------------------------------------------------------------------
	this.getCSRFToken = function()  { return this.getSession().CSRFToken };
	this.setCSRFToken = function(v) { this.getSession().CSRFToken = v };
	this.getCookies   = function()  { return this.getSession().cookies };

	// -------------------------------------------------------------------------

	// URL encoding helper (ES3 safe)
	this.urlEncode = function(str) {
		if (!str) return "";
		return java.net.URLEncoder.encode(String(str), "UTF-8");
	};

	// -------------------------------------------------------------------------
	// OAuth token acquisition. All token state read/written via session store.
	// -------------------------------------------------------------------------
	this.getOAuthToken = function() {
		var sess = this.getSession();

		// Return cached token if still valid (60s safety margin)
		if (sess.accessToken && sess.tokenExpiry) {
			var now = new java.util.Date().getTime();
			if (now < sess.tokenExpiry - 60000) return sess.accessToken;
			if (sess.refreshToken) return this.refreshOAuthToken();
		}

		if (!this.oauth2_token_url) this.throwException("OAuth2 selected but oauth2_token_url missing");
		if (!this.client_id)        this.throwException("OAuth2 selected but client_id missing");

		var grant = (this.oauth2_grant_index === 2) ? "password"
		          : (this.oauth2_grant_index === 1) ? "authorization_code"
		          : "client_credentials";

		var tokenBody = "grant_type=" + this.urlEncode(grant);

		// Client auth method:
		//   "none (public client)" -> no secret, no auth header
		//   "Client Secret Basic"  -> Authorization: Basic base64(id:secret)
		//   "Client Secret Post"   -> secret in POST body
		var m            = (this.oauth2_token_auth_method || "").toLowerCase();
		var useBasic     = (m.indexOf("basic") >= 0);
		var usePost      = (m.indexOf("post")  >= 0);
		var publicClient = (m.indexOf("none")  >= 0);

		tokenBody += "&client_id=" + this.urlEncode(this.client_id);

		if (!publicClient && this.client_secret && usePost) {
			tokenBody += "&client_secret=" + this.urlEncode(this.client_secret);
		}

		if (grant === "password") {
			if (!this.oauth2_username || !this.oauth2_password) {
				this.throwException("OAuth2 Password grant selected but oauth2_username/oauth2_password missing");
			}
			tokenBody += "&username=" + this.urlEncode(this.oauth2_username);
			tokenBody += "&password=" + this.urlEncode(this.oauth2_password);
		}

		if (grant === "authorization_code" && this.auth_code) {
			tokenBody += "&code=" + this.urlEncode(this.auth_code);
		}

		if (this.oauth2_scope)                              { tokenBody += "&scope="        + this.urlEncode(this.oauth2_scope) }
		if (this.audience)                                  { tokenBody += "&audience="     + this.urlEncode(this.audience) }
		if (this.redirect_uri && grant === "authorization_code") { tokenBody += "&redirect_uri=" + this.urlEncode(this.redirect_uri) }

		var tokenHeaders = {};
		if (!publicClient && useBasic) {
			if (!this.client_secret) this.throwException("Token auth Basic requires client_secret but it is missing");
			var credentials = this.client_id + ":" + this.client_secret;
			var encoded = new java.lang.String(
				org.apache.commons.codec.binary.Base64.encodeBase64(
					new java.lang.String(credentials).getBytes()
				)
			);
			tokenHeaders["Authorization"] = "Basic " + encoded;
		}

		var tokenResponse = this.makeRequest({
			gettingToken:       true,
			verb:               "POST",
			url:                this.oauth2_token_url,
			ctype:              "application/x-www-form-urlencoded",
			body:               tokenBody,
			headers:            tokenHeaders,
			expectedReturnType: "JS object",
			where:              "getOAuthToken()",
			skipAuth:           true
		});

		if (tokenResponse && tokenResponse.access_token) {
			sess.accessToken  = tokenResponse.access_token;
			sess.refreshToken = tokenResponse.refresh_token || null;
			if (tokenResponse.expires_in) {
				var now2 = new java.util.Date().getTime();
				sess.tokenExpiry = now2 + (parseInt(tokenResponse.expires_in, 10) * 1000);
			} else {
				sess.tokenExpiry = null;
			}
			return sess.accessToken;
		}

		this.throwException("Failed to obtain OAuth access token. Response: " + toJson(tokenResponse || {}));
	};

	// -------------------------------------------------------------------------
	// Refresh an OAuth access token. Falls back to full re-auth on failure.
	// -------------------------------------------------------------------------
	this.refreshOAuthToken = function() {
		var sess = this.getSession();

		var tokenBody = "grant_type=refresh_token&refresh_token=" + this.urlEncode(sess.refreshToken);
		tokenBody += "&client_id=" + this.urlEncode(this.client_id);
		if (this.client_secret) {
			tokenBody += "&client_secret=" + this.urlEncode(this.client_secret);
		}

		var tokenResponse = this.makeRequest({
			gettingToken:       true,
			verb:               "POST",
			url:                this.oauth2_token_url,
			ctype:              "application/x-www-form-urlencoded",
			body:               tokenBody,
			expectedReturnType: "JS object",
			where:              "refreshOAuthToken()",
			skipAuth:           true
		});

		if (tokenResponse && tokenResponse.access_token) {
			sess.accessToken  = tokenResponse.access_token;
			sess.refreshToken = tokenResponse.refresh_token || sess.refreshToken;
			if (tokenResponse.expires_in) {
				var now = new java.util.Date().getTime();
				sess.tokenExpiry = now + (parseInt(tokenResponse.expires_in, 10) * 1000);
			}
			return sess.accessToken;
		}

		// Refresh failed - clear and force full re-authentication
		this.logmsg("WARN: Token refresh failed, clearing session and re-authenticating");
		this.clearSession();
		return this.getOAuthToken();
	};

	// -------------------------------------------------------------------------
	// getToken() - called once per session (guarded by sess.gotToken).
	// Routes to the correct auth strategy and marks the session ready.
	// -------------------------------------------------------------------------
	this.getToken = function(where) {
		where = where || "";
		var sess = this.getSession();

		if (this.auth_method === "none") {
			sess.gotToken = true;
			return null;
		}

		if (this.auth_method === "basic") {
			if (!this.basic_username || !this.basic_password) {
				this.throwException("Basic auth selected but basic_username/basic_password missing");
			}
			sess.gotToken = true;
			return null;
		}

		if (this.auth_method === "apikey") {
			if (!this.api_key_value) this.throwException("API Key auth selected but api_key_value missing");
			sess.gotToken = true;
			return null;
		}

		if (this.auth_method === "bearer") {
			if (!this.bearer_token) this.throwException("Bearer Token auth selected but bearer_token missing");
			sess.gotToken = true;
			return null;
		}

		if (this.auth_method === "oauth2") {
			var tok = this.getOAuthToken();
			sess.gotToken = true;
			return tok;
		}

		// ITIM: two-step login - POST credentials, then GET /me for CSRF token
		if (this.auth_method === "itim") {
			// Reset session before re-authenticating
			sess.cookies    = system.newAttribute("http.Cookie");
			sess.CSRFToken  = null;
			sess.LTPAToken2 = null;

			// Step 1: POST to j_security_check to get LTPA cookies
			this.makeRequest({
				gettingToken:       true,
				verb:               "POST",
				url:                this.itim_login_endpoint,
				ctype:              "application/x-www-form-urlencoded",
				body:               "j_username=" + this.urlEncode(this.itim_username) + "&j_password=" + this.urlEncode(this.itim_password),
				expectedReturnType: "entry",
				where:              "getToken(itim-login)"
			});

			// Step 2: GET /me to capture CSRF token from response header
			var meReply = this.makeRequest({
				gettingToken:       true,
				verb:               "GET",
				url:                this.itim_me_endpoint,
				ctype:              "application/json",
				expectedReturnType: "entry",
				where:              "getToken(itim-me)"
			});

			sess.gotToken = true;
			return meReply;
		}

		if (this.auth_method === "custom") {
			sess.gotToken = true;
			return null;
		}

		sess.gotToken = true;
		return null;
	};

	// Assemble a URL from an array of parts, deduplicating overlapping segments
	this.assembleUrl = function(where, partsArray) {
		if (!(partsArray instanceof Array)) partsArray = [partsArray];
		var url      = "";
		var lastpart = "";
		for (var i = 0; i < partsArray.length; i++) {
			var part   = (partsArray[i] || "").trim();
			var lcpart = part.toLowerCase();
			if (!part) continue;

			// Remove overlap with previous segment
			if (part.indexOf(lastpart) === 0) {
				part = part.substring(lastpart.length);
			}

			// Strip UID path placeholders like /{uid}
			part = part.replace(/\/\{[^}]*\}/g, "");

			// Normalise slashes
			if (part.charAt(0) === "/")                  { part = part.substring(1) }
			if (part.charAt(part.length - 1) === "/")    { part = part.substring(0, part.length - 1) }

			if (part.indexOf("https://") === 0) {
				url = part;
			} else {
				url += ((i > 0) ? "/" : "") + part;
			}

			lastpart = lcpart;
		}
		return url;
	};

	// -------------------------------------------------------------------------
	// applyAuthentication() - injects credentials into the request entry or URL.
	// -------------------------------------------------------------------------
	this.applyAuthentication = function(reqEntry, finalUrl, skipAuth, where) {
		if (skipAuth) return { url: finalUrl };

		// Custom: hand off to injected script
		if (this.auth_method === "custom" && this.custom_auth_script) {
			try {
				var client = this, requestEntry = reqEntry, url = finalUrl;
				eval(this.custom_auth_script);
			} catch (e) {
				this.throwException("Custom auth script failed: " + e);
			}
			return { url: finalUrl };
		}

		// Basic: FIX - use basic_username/basic_password (not legacy this.username)
		if (this.auth_method === "basic") {
			var credentials = this.basic_username + ":" + this.basic_password;
			var encoded = new java.lang.String(
				org.apache.commons.codec.binary.Base64.encodeBase64(
					new java.lang.String(credentials).getBytes()
				)
			);
			reqEntry["http.Authorization"] = "Basic " + encoded;
			return { url: finalUrl };
		}

		// API Key: header or query string
		if (this.auth_method === "apikey") {
			if (!this.api_key_value) this.throwException("API Key auth selected but api_key_value missing");
			var name = String(this.api_key_name     || "X-API-Key").trim();
			var loc  = String(this.api_key_location || "Header").toLowerCase().trim();
			var val  = String(this.api_key_value).trim();
			if (loc === "header") {
				reqEntry["http." + name] = val;
			} else if (loc === "query") {
				var sep = (finalUrl.indexOf("?") >= 0) ? "&" : "?";
				finalUrl = finalUrl + sep + this.urlEncode(name) + "=" + this.urlEncode(val);
			} else {
				this.throwException("Unsupported api_key_location: " + this.api_key_location + " (use Header or Query)");
			}
			return { url: finalUrl };
		}

		// Bearer: static token in Authorization header
		if (this.auth_method === "bearer") {
			var headerName = (this.token_header_name || "Authorization");
			var prefix     = String(this.token_prefix || "bearer").trim();
			var token      = String(this.bearer_token || "").trim();
			if (token !== "") {
				reqEntry["http." + headerName] = prefix + " " + token;
			}
			return { url: finalUrl };
		}

		// OAuth2: retrieve token from session (fetch/refresh as needed)
		if (this.auth_method === "oauth2") {
			var tok = String(this.getOAuthToken() || "").trim();
			if (tok !== "") {
				var headerName = (this.oauth2_token_header_name || "Authorization");
				var prefix     = String(this.oauth2_token_prefix || "bearer").trim();
				reqEntry["http." + headerName] = prefix + " " + tok;
			}
			return { url: finalUrl };
		}

		// ITIM: cookies and CSRF injected directly in makeRequest()
		return { url: finalUrl };
	};

	// -------------------------------------------------------------------------
	// makeRequest() - core HTTP dispatch
	//
	// Key params:
	//   verb            {string}   HTTP verb (default GET)
	//   url             {string}   path or full URL
	//   body            {string}   request body (POST/PUT)
	//   ctype           {string}   Content-Type
	//   accept          {string}   Accept header
	//   headers         {object}   additional headers
	//   expectedReturnType {string} "JS object" | "entry"
	//   where           {string}   caller label for logging
	//   gettingToken    {boolean}  suppress auth during token fetch
	//   skipAuth        {boolean}  bypass applyAuthentication entirely
	//   ishref          {boolean}  strip base/root from full href
	//   contextRoot     {string}   override this.contextRoot
	//   sessionKey      {string}   use a specific named session
	// -------------------------------------------------------------------------
	this.makeRequest = function(params) {
		var sess = this.getSession(params.sessionKey);

		// Authenticate before first real request (exempt: token fetches, schema loads)
		var whereStr      = params.where || "";
		var isFetchSchema = (whereStr.indexOf("fetchSchema") === 0); // ES3-safe
		if (!sess.gotToken && !this.gettingToken && !isFetchSchema) {
			this.gettingToken = true;
			this.getToken(whereStr);
			this.gettingToken = false;
			sess.gotToken = true;
		}
/*
		var msg = "-> makeRequest(\n";
		for (var pname in params) { msg += "   " + pname + ": " + params[pname] + "\n" }
		this.logmsg(msg);
*/
		var verb         = params.verb   || "GET";
		var url          = params.url    || this.throwException("makeRequest called with no URL");
		var p;
		var body         = params.body   || null;
		var ctype        = params.ctype;
		var accept       = params.accept;
		var where        = whereStr;
		var headers      = params.headers || {};
		var gettingToken = params.gettingToken || false;
		var username     = params.username || "";
		var password     = params.password || "";
		var contextRoot  = (typeof(params.contextRoot) == "undefined") ? this.contextRoot : params.contextRoot;
		var skipAuth     = params.skipAuth  || false;
		var returnType   = params.expectedReturnType || "JS object";

		// Strip base/root/query from a full href before assembly
		if (params.ishref) {
			var urlLc  = url.toLowerCase();
			var baseLc = this.baseUrl.toLowerCase();
			var rootLc = this.contextRoot.toLowerCase();
			if (urlLc.indexOf(baseLc) === 0)        { url = url.substring(this.baseUrl.length) }
			if (url.toLowerCase().indexOf(rootLc) === 0) { url = url.substring(this.contextRoot.length) }
			if ((p = url.indexOf("?")) > 0)         { url = url.substring(0, p) }
		}

		var alreadyImportedCert = false;

		java.lang.Runtime.getRuntime().gc();

		this.requestEntry.removeAllAttributes();

		// Assemble final URL
		if (gettingToken || where.equalsIgnoreCase("fetchSchema()")) {
			url = this.assembleUrl(where, [this.baseUrl, url]);
		} else {
			url = this.assembleUrl(where, [this.baseUrl, contextRoot, url]);
		}

		// Serialize body for POST/PUT
		if (typeof(body) != "undefined" && body !== null && ("POST".equalsIgnoreCase(verb) || "PUT".equalsIgnoreCase(verb))) {
			if (typeof body != "string") {
				try   { body = toJson(body) }
				catch (ex) { body = String(body) }
			}
			this.requestEntry["http.body"] = body;
		}

		this.http.setParam("method", verb.toUpperCase());
		this.http.setParam("url", url);
		this.http.setParam("username", username);
		this.http.setParam("password", password);

		this.requestEntry["http.url"]    = url;
		this.requestEntry["http.method"] = verb.toUpperCase();
		if (verb == "PUT" || verb == "POST") {
			if (ctype != null)                          { this.requestEntry["http.Content-Type"] = ctype }
			if (body != null && body.trim && body.trim()) { this.requestEntry["http.body"]  = body }
		}
		if (accept != null) { this.requestEntry["http.Accept"] = accept }

		if (username != "") {
			this.requestEntry["http.remote_user"]     = username;
			this.requestEntry["http.remote_password"] = password;
		}

		for (var hdr in headers) {
			if (headers[hdr] != null) { this.requestEntry["http." + hdr] = headers[hdr] }
		}

		// Apply auth strategy (may rewrite URL for API key query mode)
		var authResult = this.applyAuthentication(this.requestEntry, url, skipAuth, where);
		url = authResult.url;
		this.requestEntry["http.url"] = url;
		this.http.setParam("url", url);

		this.http.terminate();
		this.http.initialize(null);

		alreadyImportedCert = false;
		var reply = null;

		do {
			var retry = false;
			try {
				// Inject session cookies and CSRF token
				this.requestEntry.setAttribute("http.Cookie", sess.cookies);
				if (sess.CSRFToken) {
					this.requestEntry["http.CSRFToken"] = sess.CSRFToken;
				}
				this.requestEntry["http.Cache-Control"] = "no-cache";

				// *************************************************************
				// Make the actual HTTP request
				// *************************************************************
				this.logDetails({ msg: "\n--->>> Request", entry: this.requestEntry, where: where, sent: true });

				var retEntry = this.http.queryReply(this.requestEntry);

				this.logDetails({ msg: "<<<--- Response", entry: retEntry, where: where, sent: false });

				// *************************************************************
				// After the HTTP request
				// *************************************************************

				retEntry["http.url"] = url;

				// Merge Set-Cookie headers into the session cookie jar
				if (retEntry["http.Set-Cookie"]) {
					for (var cookie in retEntry["http.Set-Cookie"]) {
						var parts = system.splitString(cookie, "=");
						for (var val in sess.cookies) {
							if (val.indexOf(parts[0]) === 0) { // ES3-safe startsWith
								sess.cookies.removeValue(val);
							}
						}
						sess.cookies.addValue(cookie);
					}
				}

				// Capture CSRF token from response (ITIM)
				if (retEntry.getString("http.CSRFToken")) {
					sess.CSRFToken = retEntry.getString("http.CSRFToken");
				}

				var retCode = retEntry.getString("http.responseCode");

				if ("findEntry()".equalsIgnoreCase(where) && retCode == "404") {
					return null;
				} else
				if (retCode == "401") {
					if (this.auth_method === "oauth2" && sess.refreshToken) {
						sess.accessToken = null;
						sess.gotToken    = false;
						retry = true;
					} else {
						this.throwException("Unauthorized - authentication failed");
					}
				} else
				if (retCode.indexOf("4") === 0 && retCode != "404") {
					try {
						var response = fromJson(retEntry.getString("http.bodyAsString") || "{}");
						var errmsg   = response.text || "";
						if (errmsg.toLowerCase().indexOf("ldap: error code 32") >= 0) { return null }
					} catch (ex) { /* not JSON - fall through */ }
				}

				if (!retry) {
					reply = this.parseReply(this.requestEntry, retEntry, returnType, gettingToken, where);
				}

			} catch (ex) {
				if (ex.toString().indexOf("Unauthorized") >= 0) {
					sess.gotToken = false;
					this.getToken();
					retry = true;
				} else
				if (ex instanceof javax.net.ssl.SSLHandshakeException) {
					if ((ex.toString().indexOf("Certificate chaining error") >= 0) && alreadyImportedCert) {
						this.throwException("You must restart the SDI server for the imported certificate to be trusted.");
					}
					this.getCertificate();
					alreadyImportedCert = true;
					retry = true;
				} else
				if (typeof retEntry != "undefined" && retEntry && retEntry.getString("http.responseCode").indexOf("3") === 0 && !gettingToken) {
					this.requestEntry["http.url"] = retEntry.getString("http.Location");
					retry = true;
				} else {
					throw ex;
				}
			}
		} while (retry);

		return reply;
	};

	// Strip verbose attributes from an Entry for cleaner logging
	this.reduceEntry = function(entryArg) {
		var entry = entryArg.clone();
		entry.removeAttribute("http.base");
		entry.removeAttribute("http.body.response");
		entry.removeAttribute("http.ipaddress");
		entry.removeAttribute("http.bodyAsBytes");
		return entry;
	};

	// Release all resources and clear all sessions
	this.terminate = function() {
		this.http.terminate();
		this.sessions = {};
		this.logmsg("RESTCLIENT terminated, all sessions cleared");
	};

	// Import the server SSL certificate into the TDI keystore
	this.getCertificate = function() {
		this.logmsg("! Getting client cert");
		var msg = com.ibm.di.security.GetSSLCertificate.installCertificateFrom(this.baseUrl, 443);
		this.logmsg("! Result: " + msg);
	};

	// Log details of a request or response Entry
	this.logDetails = function(params, sent) {
		// @@DEBUG comment out next line for more output
		return;

		sent = sent || false;
		var msg   = params.msg   || "";
		var entry = params.entry;
		var url   = params.url || "";
		var verb  = params.verb || "";
		var ctype = params.ctype || "";
		var where = params.where || "";
		var s     = new java.lang.StringBuffer();
		s.append(msg + "  -  called from: " + where + " ");
//		if (verb  != null) { s.append("   " + verb.toUpperCase()) }
//		if (ctype != null) { s.append("   " + ctype) }
//		if (url   != null) { s.append("   " + url) }
		s.append("\n");
		if (entry != null) {
			if (entry instanceof com.ibm.di.entry.Entry) {
				s.append(this.entryDetails(entry, sent));
			} else {
				s.append(entry.toString());
			}
		}
		this.logmsg(s.toString());
		//java.lang.System.out.println(s.toString());
		if (typeof(alert) == "function") alert(s.toString());
	};

	this.throwException = function(msg) {
		throw new java.lang.Exception(msg);
	};

	// Validate HTTP response and extract body as JS object or Entry
	this.parseReply = function(requestEntry, replyEntry, returnType, gettingToken, where) {
		if (replyEntry === null) { return }

		var resCode = replyEntry.getString("http.responseCode");

		if (resCode == "302" && gettingToken) {
			// 302 during token acquisition is expected for ITIM
		} else
		if (resCode == "404") {
			return null;
		} else
		if (resCode.indexOf("2") !== 0 && !((resCode == "400") && gettingToken)) {
			var errMsg = where + " - Error response from server. Response code: "
								+ resCode
								+ "\n    Message: " + replyEntry.getString("http.responseMsg")
								+ "\n      Error: " + replyEntry.getString("http.bodyAsString");
			if (this.debug) {
				errMsg += ("\n---> Request: " + requestEntry + "\n===> Reply: " + replyEntry);
			}
			this.throwException(errMsg);
		}

		if (!"JS object".equalsIgnoreCase(returnType)) {
			return replyEntry;
		}

		var body = replyEntry.getString("http.bodyAsString");
		try {
			var reply = fromJson(body || '{"result": "Add request being processed"}');
		} catch (ex) {
			this.throwException("Error parsing return payload: " + ex.toString()
				+ "\n*** request ***\n" + this.requestEntry
				+ "\n*** reply ***\n"   + replyEntry);
		}
		return reply;
	};

	this.LJ = function(txt, len) {
		txt = txt || "";
		len = len || txt.length;
		return (txt + "                                                       ").substring(0, len);
	};

	this.entryDetails = function(entry, sent) {
		if (!entry) return "";
		var entry = this.reduceEntry(entry);
		if (typeof(sent) == "undefined") sent = false;
		var txt = "";
		for (var att in entry) {
			var name = att.getName();
			var val  = att.toString().substring(0, 1024);
			txt += "  " + name + ": " + val + "\n";
		}
		return txt;
	};

	this.logmsg = function(lvl, msg) {
		if (!lvl) {
			lvl = "INFO"; msg = "";
		} else if (!msg) {
			msg = lvl; lvl = "INFO";
		}
		if (typeof(task) != "undefined") {
			task.logmsg(lvl, msg);
//			java.lang.System.out.println(((lvl == "INFO") ? "" : lvl) + msg);
		} else {
			main.logmsg(lvl, msg);
		}
	};
}

// 20250121 1145 Change parseOpenAPIschema so the argument openApiSchema can be either JSON or JS object
// 20250128 1552 Updated replaceEmbeddedUID() to accept either an Entry or a string value as the criteria argument
// 20250129 1645 Fixing getChildren so it works (again) - stumbled on "parameters"
// 20250702 1334 Fixed fatal flow in getChildren()
// 20251007 1145 Added method to check that a path supports a given verb: pathSupportsVerb()
// 20251027 2001 Fixed pathSupportsVerb()
// 20251109 2220 Changing the schemaObj from JS Object to an hierarchical Entry - fingers crossed
// 20251110 1554 Added endpointPathNameIterator
// 20251112 1522 Lots of reworking now that schemaObj is an Entry instead of JS Object
// 20251116 1643 .getParameters() now works correctly with schemaObj == Entry and only finds for /path and with uid
// 20251118 1246 preventing getParameters() from adding the same param more than once to the set returned
// 20251217 1405 Corrected a bug in getAcceptType() - was looking in the wrong part of the schema
// 20251227 1422 Fixed getChildren() to deal with parts of the path that do not work with Entry/Attribute dot notation
// 20251228 1526 Finally handling getContentType and getAcceptType right
// 20251229 1244 Set default type to application/json & are handling oneOf spec for schema
// 20251229 1539 Fixed getAcceptType and getContentType to deal with the funky, inconsistent schema
// 20260101 1616 Got rid of potential runaway loops for getting Accept and Content Types
// 20260107 1445 Changed the get*Type() functions to return null if nothing found
// 20260310 1513 Corrected this.pathSupportsVerb by changing it to use .getChildren

function SCHEMA(schema, format) {
	_WHERE = "SCHEMA class";	/* Global variable available for error reporting */
	this.name = "SCHEMA";
	this.schemaObj = system.newEntry();

	/* Main init logic after method definitions

	The name says it all. Returns a JS Obj */

	this.parseOpenAPIschema = function (openApiSchema) {
		try {
			if (typeof (openApiSchema) != "string") return openApiSchema;

			openApiSchema = openApiSchema.trim();
			var jsonString = "";

			/* Load Jackson libraries */
			var ObjectMapper = com.fasterxml.jackson.databind.ObjectMapper;
			var objectMapper = new ObjectMapper();

			if (openApiSchema.startsWith("{") && (openApiSchema.endsWith("}") >= 0)) {
				// overriding above arguments - for now
				this.format = "JSON"
			} else {
				this.format = "YAML"
			}

			/* Check if YAML and if so, convert to Json */
			if ("YAML".equalsIgnoreCase(this.format)) {
				/* Use SnakeYAML to convert the YAML to a map that the ObjectMapper can read */
				var Yaml = Packages.org.yaml.snakeyaml.Yaml;
				/* Create instances of Yaml and ObjectMapper */
				var yaml = new Yaml();
				/* Parse YAML into a Java Map */
				var map = yaml.load(openApiSchema);

				/* Convert Java Map to JSON string */
				jsonString = objectMapper.writeValueAsString(map)
			} else {
				jsonString = openApiSchema;
			}

			// Now to read it into an Entry object so we get a DOM model with xpath
			var file = system.getConnector("ibmdi.FormEntryConnector");
			file.setParam("entryRawData", jsonString);
			var JSONParser = system.getParser("ibmdi.JSONParser");
			file.setParser(JSONParser);
			file.initialize(null);
			file.selectEntries();
			var schemaEntry = file.getNextEntry();

			this.schemaObj = schemaEntry;

			// For future convenience, we want to create a sorted Array of endpoint names
			var hmap = new java.util.HashMap();
			var nodelist = this.schemaObj.paths.getChildNodes(); // Entry/Attribute classes implement the DOM Interface
			var size = nodelist.getLength();
			for (var i = 0; i < size; i++) {
				hmap.put(nodelist.item(i).getName(), true)
			}
			this.endpointPathArray = hmap.keySet().toArray();
			java.util.Arrays.sort(this.endpointPathArray);

			// And finally, create the handy endpointPathIterator object
			this.endpointPathIterator = this.makeEndpointPathArray(this.endpointPathArray)

			return this.schemaObj
		} catch (ex) {
			throw "SCHEMA.parseSchema() - " + ex
		}

	}

	/*
	Parses the path and returns the name of the embedded UID attribute in the URL
	*/
	this.getEmbeddedUID = function (path) {
		var parts = system.splitString(path, "/");

		for (var i = 0; i < parts.length; i++) {
			var part = parts[i].trim();
			if (part.startsWith("{") && part.endsWith("}")) {
				// Found an embedded uid
				return part.substring(1, part.length - 1)
			}
		}
		return null
	}

	/*
	Replaces the uid placeholder in the URL path with the uid value passed
	The criteria argument is either an Entry or a string value
	*/
	this.replaceEmbeddedUID = function (path, criteria) {
		var parts = system.splitString(path, "/");
		var newPath = [parts[0]];

		for (var i = 1; i < parts.length; i++) {
			var part = parts[i].trim();
			if (part.startsWith("{") && part.endsWith("}")) {
				// Found an embedded uid
				var embeddedUID = part.substring(1, part.length - 1);

				// If criteria is an Entry then grab the attribute value, else use the parameter value itself
				var uidValue = (criteria instanceof com.ibm.di.entry.Entry) ? entry[embeddedUID] : criteria;

				if (!uidValue) {
					throw new java.lang.Exception("UID attribute not mapped out or is null: " + embeddedUID)
				}
				newPath.push(uidValue)
			} else {
				newPath.push(part)
			}
		}
		return newPath.join("/")
	}

	/*
	Uses .getChildren() to return the parameters array for the chosen path and action.
	And it must return parameters for both /endpoint and /endpoint/{uid}
	*/
	this.useEntry = system.newEntry();
	this.getParameters = function (path, verb) {
		var params = [];
		var alreadyAdded = {};

		verb = (verb || "").toLowerCase();
		var endpointPath = this.endpointPathIterator.getFirst(path);
		while (endpointPath != null && endpointPath.startsWith(path)) {
			if (endpointPath.equals(path) ||
				(endpointPath.startsWith(path + "/{") && endpointPath.endsWith("}"))) {
				var epParams = this.getChildren(["paths", endpointPath, verb, "parameters"]);

				if (epParams != null) {
					var children = epParams.getChildNodes();
					for (var child in children) {
						this.useEntry.parameters = child;
						var jsonString = this.useEntry.toJSON();
						jsonString = jsonString.substring(14); // Remove the Attribute name
						var paramObj = fromJson(jsonString.substring(0, jsonString.length - 1)); // Create a JS object
						if (!alreadyAdded[paramObj.name]) {
							params.push(paramObj); // Add it to the array of parameters to pass back
							alreadyAdded[paramObj.name] = true
						}
					}
				}
			}

			endpointPath = this.endpointPathIterator.getNext()
		}

		return params
	}

	/*
	* !!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!
	* 
	* 	Just like with parameters, we have to look for the path, also with {id} in the URI 
	* 
	*  * !!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!
	* 
	*/
	this.defaultType = function (path, verb) {
		//    	if (path.toLowerCase().indexOf("rest/v")) {
		//    		return "application/vnd.ibm.isim-v1+json"
		//    	} else {
		return "application/json"
		//    	}		
	}

	this.getAcceptType = function (path, verb) {
		verb = (verb || "").toLowerCase();

		var endpointPath = this.endpointPathIterator.getFirst(path);

		// If this is a write operation, then the path must include /{id}
		if (verb == "put" || verb == "delete") {
			while (endpointPath != null && endpointPath.startsWith(path)
				&& !(endpointPath.indexOf("/{") > 0 && endpointPath.endsWith("}"))) {
				endpointPath = this.endpointPathIterator.getNext()
			}
		}

		// Now to look for responses for the various responseCodes			
		while (endpointPath != null && endpointPath.startsWith(path)) {
			if (endpointPath.equals(path) ||
				(endpointPath.startsWith(path + "/{") && endpointPath.endsWith("}"))) {
				var responseCodes = this.getChildren([
					"paths", endpointPath, verb,
					"responses"
				]);

				if (responseCodes != null) {
					for (var code in responseCodes) {
						if (code.content) {
							for (var contentType in code.content) {
								return contentType.getName().replaceAll("\\\\", "")
							}
						}
					}
				}
			}

			endpointPath = this.endpointPathIterator.getNext()
		}

		//throw "SCHEMA.getAcceptType() unable to find content type for " + path
		return null
	}

	/*
	* !!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!
	* 
	* 	Just like with parameters, we have to look for the path, also with {id} in the URI 
	* 
	*  * !!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!
	* 
	*/
	this.getContentType = function (path, verb) {
		verb = (verb || "").toLowerCase();

		var endpointPath = this.endpointPathIterator.getFirst(path);
		while (endpointPath != null && endpointPath.startsWith(path)) {
			if (endpointPath.equals(path) ||
				(endpointPath.startsWith(path + "/{") && endpointPath.endsWith("}"))) {
				var content = this.getChildren([
					"paths", endpointPath, verb,
					"requestBody", "content"
				]);

				if (content != null) {
					for (var accept in content) {
						return accept.getName()
					}
				}
			}

			endpointPath = this.endpointPathIterator.getNext()
		}

		//throw "SCHEMA.getContentType() unable to find content type for " + path
		return null
	}

	/* Returns the child elements (JS Obj) of the specified path
	  Root level if no argument or blank text passed. Always return a JS object
	  */
	this.getChildren = function (path) {
		//var children = {};
		var children;

		if (!path) {
			path = []
		}
		else
			if (!(path instanceof Array)) {
				path = [path]
			}

		// NB!! Here you must deal with path parts that have special characters - like slashes (roles/orgroles)
		//      So you have to construct the attribute reference by hand

		// var expr = "//paths/path[@name=" + xpathLiteral("/people") + "]/post";
		if (path.length > 1) {
			var attName = "[\"" + path[0] + "\"]";
			for (var i = 1; i < path.length; i++) {
				var part = path[i];
				/*        		
				if (this.isValidDotName(part)) {
				attName += "." + part
				} else {
				attName += "['" + part + "']"
				}
				*/
				attName += "[\"" + part + "\"]";

				var testChildren = eval("this.schemaObj" + attName);
				if (testChildren == null) return null;
			}

			children = testChildren
		} else {
			children = this.schemaObj.paths
		}

		return children;
	}

	// Store the unique identifer field for each item (people, lifecyclerules, ...)
	this.getEndpointIdFieldNames = function () {
		var endpointIdFieldNames = {};
		var endpoints = this.getChildren("paths");
		for (var endpointURI in endpoints) {
			if (endpointURI.getName().indexOf("}") >= 0) {
				var re = /^\/?([A-Za-z0-9_-]+)\/\{([A-Za-z0-9_-]+)\}\/?$/; // Returns the endpoint and the unique id attribute (in braces)
				var pair = re.exec(endpointURI.getName());
				if (pair) {
					endpointIdFieldNames[pair[1]] = pair[2]
				}
			}
		}

		return endpointIdFieldNames
	}

	// Creates a handy Iterator object over all Strings in the sorted Array passed (arr)
	this.makeEndpointPathArray = function (arr) {
		// lowerBound: first index i where arr[i] >= key (lexicographic)
		function lowerBound(a, key) {
			var lo = 0, hi = a.length;
			while (lo < hi) {
				var mid = (lo + hi) >> 1;
				if (a[mid] < key) lo = mid + 1;
				else hi = mid;
			}
			return lo;
		}

		var lo = 0, hi = 0, cur = -1;

		return {
			// returns first matching String, else -1
			getFirst: function (prefix) {
				lo = lowerBound(arr, prefix);
				hi = lowerBound(arr, prefix + "\uffff"); // just beyond the prefix range
				if (lo < hi) {
					cur = lo;
					return arr[lo];
				}
				cur = -1;
				return null;
			},
			// returns next matching String, else -1
			getNext: function () {
				var n = cur + 1;
				if (n >= lo && n < hi) {
					cur = n;
					return arr[n];
				}
				return null;
			},
			reset: function () { lo = hi = 0; cur = -1; }
		};
	}

	// Check the schema for an endpoint support the supplied verb (GET, POST, PUT or DELETE)
	this.pathSupportsVerb = function (path, verb) {
		verb = (verb || "").toUpperCase();
		var children = this.getChildren(["paths", path, verb])
		return children != null
	}

	/* Main init logic */
	this.schemaArg = schema;
	this.format = format || "YAML";
	this.schemaObj = this.parseOpenAPIschema(schema);
	this.endpointIdFieldNames = this.getEndpointIdFieldNames()
}

waitTime = 5; // seconds
alreadyLogged = {};
cnt = 0;

function prettyJson(jsonString, indentSize) {
	if (indentSize === undefined || indentSize === null) indentSize = 4;

	// Build one indent unit (ES3-safe)
	var indentUnit = "";
	for (var i = 0; i < indentSize; i++) indentUnit += " ";

	var out = "";
	var depth = 0;
	var inString = false;
	var escapeNext = false;

	// Small helper to emit indentation
	function emitIndent(n) {
		for (var k = 0; k < n; k++) out += indentUnit;
	}

	// Trim leading/trailing whitespace without ES5 .trim()
	jsonString = jsonString.replace(/^\s+/, "").replace(/\s+$/, "");

	for (var p = 0; p < jsonString.length; p++) {
		var ch = jsonString.charAt(p);

		if (inString) {
			out += ch;

			if (escapeNext) {
				escapeNext = false;
			} else if (ch === "\\") {
				escapeNext = true;
			} else if (ch === "\"") {
				inString = false;
			}
			continue;
		}

		// Not in string
		if (ch === "\"") {
			inString = true;
			out += ch;
		} else if (ch === "{" || ch === "[") {
			out += ch;
			out += "\n";
			depth++;
			emitIndent(depth);
		} else if (ch === "}" || ch === "]") {
			out += "\n";
			depth--;
			if (depth < 0) depth = 0;
			emitIndent(depth);
			out += ch;
		} else if (ch === ",") {
			out += ch;
			out += "\n";
			emitIndent(depth);
		} else if (ch === ":") {
			out += ": ";
		} else if (ch === " " || ch === "\t" || ch === "\r" || ch === "\n") {
			// Skip whitespace outside strings (prettifier normalizes it)
		} else {
			out += ch;
		}
	}

	return out;
}

function prettyJsonFANCY(jsonString) {
	// Import org.json classes
	var JSONObject = Packages.org.json.JSONObject;
	var JSONArray  = Packages.org.json.JSONArray;

	// Trim leading whitespace to detect type
	var trimmed = jsonString.replace(/^\s+/, "");

	// Choose parser based on first non-whitespace char
	if (trimmed.charAt(0) === "{") {
		var obj = new JSONObject(jsonString);
		return obj.toString(4); // indent = 4
	} else if (trimmed.charAt(0) === "[") {
		var arr = new JSONArray(jsonString);
		return arr.toString(4);
	} else {
		throw "Invalid JSON: must start with '{' or '['";
	}
}

function waitingFor(why) {
	task.logmsg("...waiting " + waitTime + " seconds for " + (why || "previous write operation to be completed"))
	system.sleep(waitTime);
	task.logmsg("Continuing...")
}

function supportsMode(mode) {
	// Default to all modes being supported
	var modesSupported = system.getExternalProperty("modes")
		|| "iterator,addonly,lookup,update,delete";
	modesSupported = modesSupported.trim().toLowerCase();
	mode = mode.trim().toLowerCase();

	var supported =  modesSupported.indexOf(mode) >= 0;
	if (!supported) {
		task.logmsg(thisConnector.getName() + " mode not listed in the Property 'mode': " + mode)
	}

	return supported
}

function beforeExecute(mode) {
	mode = mode.toLowerCase();
	if (alreadyLogged[thisConnector.getName()]) return;

	alreadyLogged[thisConnector.getName()] = true;

	if (!supportsMode(mode)) {
		system.ignoreEntry();	
	}
	task.logmsg("\n----- " + thisConnector.getName() + ":")
}

{
  "openapi": "3.0.0",
  "info": {
    "title": "JSONPlaceholder",
    "version": "1.0.0"
  },
  "servers": [
    {
      "url": "https://jsonplaceholder.typicode.com"
    }
  ],
  "paths": {
    "/users": {
      "get": {
        "summary": "List all users",
        "parameters": [
          {
            "name": "id",
            "in": "query",
            "required": false,
            "description": "Filter by user ID",
            "schema": { "type": "integer" }
          },
          {
            "name": "username",
            "in": "query",
            "required": false,
            "description": "Filter by username",
            "schema": { "type": "string" }
          }
        ],
        "responses": {
          "200": {
            "description": "A list of users",
            "content": {
              "application/json": {
                "schema": {
                  "type": "array",
                  "items": { "$ref": "#/components/schemas/User" }
                }
              }
            }
          }
        }
      }
    },
    "/users/{id}": {
      "get": {
        "summary": "Get a single user",
        "parameters": [
          {
            "name": "id",
            "in": "path",
            "required": true,
            "description": "User ID",
            "schema": { "type": "integer" }
          }
        ],
        "responses": {
          "200": {
            "description": "A single user",
            "content": {
              "application/json": {
                "schema": { "$ref": "#/components/schemas/User" }
              }
            }
          }
        }
      }
    }
  },
  "components": {
    "schemas": {
      "User": {
        "type": "object",
        "properties": {
          "id":       { "type": "integer" },
          "name":     { "type": "string" },
          "username": { "type": "string" },
          "email":    { "type": "string" },
          "phone":    { "type": "string" },
          "website":  { "type": "string" }
        }
      }
    }
  }
}

